  1→/**
  2→ * RideCircle API Client
  3→ * Fetch-based REST client for the ThinkPHP backend
  4→ */
  5→var RCApi = (function() {
  6→    'use strict';
  7→
  8→    var BASE_URL = '/api';
  9→
 10→    function request(method, path, data, options) {
 11→        options = options || {};
 12→        var url = BASE_URL + path;
 13→        var fetchOpts = {
 14→            method: method.toUpperCase(),
 15→            credentials: 'include',
 16→            headers: {}
 17→        };
 18→
 19→        // Add auth token if stored
 20→        var token = localStorage.getItem('rc_api_token');
 21→        if (token) {
 22→            fetchOpts.headers['Authorization'] = 'Bearer ' + token;
 23→        }
 24→
 25→        // Handle query params for GET
 26→        if (method === 'GET' && data) {
 27→            var qs = RCUtil.buildQuery(data);
 28→            url += qs;
 29→        }
 30→
 31→        // Handle body for POST/PUT
 32→        if ((method === 'POST' || method === 'PUT' || method === 'PATCH') && data) {
 33→            if (data instanceof FormData) {
 34→                // Don't set Content-Type for FormData — browser sets boundary
 35→                fetchOpts.body = data;
 36→            } else {
 37→                fetchOpts.headers['Content-Type'] = 'application/json';
 38→                fetchOpts.body = JSON.stringify(data);
 39→            }
 40→        }
 41→
 42→        return fetch(url, fetchOpts).then(function(response) {
 43→            // Handle non-JSON responses
 44→            var contentType = response.headers.get('content-type') || '';
 45→            if (!contentType.includes('application/json')) {
 46→                if (!response.ok) {
 47→                    throw { status: response.status, message: 'Server error (' + response.status + ')' };
 48→                }
 49→                return response.text().then(function(text) {
 50→                    return { data: text };
 51→                });
 52→            }
 53→
 54→            return response.json().then(function(json) {
 55→                // ThinkPHP convention: code === 0 means success
 56→                if (json.code === 0 || json.code === 200 || response.ok) {
 57→                    return json.data !== undefined ? json.data : json;
 58→                }
 59→
 60→                // Validation errors
 61→                if (json.code === 40001 || json.code === 422) {
 62→                    var err = new Error(json.msg || json.message || 'Validation error');
 63→                    err.errors = json.errors || json.data || {};
 64→                    err.code = json.code;
 65→                    throw err;
 66→                }
 67→
 68→                // Auth errors
 69→                if (response.status === 401 || json.code === 401) {
 70→                    localStorage.removeItem('rc_api_token');
 71→                    if (window.location.hash !== '#/login') {
 72→                        window.location.hash = '#/login';
 73→                    }
 74→                    throw { status: 401, message: 'Session expired. Please log in again.' };
 75→                }
 76→
 77→                // Rate limiting
 78→                if (response.status === 429 || json.code === 429) {
 79→                    layui.layer.msg('Too many requests. Please wait a moment.', { icon: 2, time: 3000 });
 80→                    throw { status: 429, message: 'Rate limited' };
 81→                }
 82→
 83→                // Forbidden
 84→                if (response.status === 403 || json.code === 403) {
 85→                    throw { status: 403, message: json.msg || json.message || 'You do not have permission for this action.' };
 86→                }
 87→
 88→                // Not found
 89→                if (response.status === 404 || json.code === 404) {
 90→                    throw { status: 404, message: json.msg || json.message || 'Resource not found.' };
 91→                }
 92→
 93→                // General error
 94→                throw { status: response.status, code: json.code, message: json.msg || json.message || 'An error occurred.' };
 95→            });
 96→        }).catch(function(err) {
 97→            // Network errors
 98→            if (err instanceof TypeError && err.message.includes('fetch')) {
 99→                layui.layer.msg('Network error. Please check your connection.', { icon: 2, time: 3000 });
100→                throw { status: 0, message: 'Network error' };
101→            }
102→            throw err;
103→        });
104→    }
105→
106→    return {
107→        get: function(path, params) { return request('GET', path, params); },
108→        post: function(path, data) { return request('POST', path, data); },
109→        put: function(path, data) { return request('PUT', path, data); },
110→        del: function(path) { return request('DELETE', path); },
111→        upload: function(path, formData) { return request('POST', path, formData); },
112→
113→        // ---- Auth ----
114→        login: function(email, password) { return this.post('/auth/login', { email: email, password: password }); },
115→        register: function(data) { return this.post('/auth/register', data); },
116→        logout: function() { return this.post('/auth/logout'); },
117→        me: function() { return this.get('/auth/me'); },
118→
119→        // ---- Tokens ----
120→        getTokens: function() { return this.get('/auth/tokens'); },
121→        createToken: function(data) { return this.post('/auth/tokens', data); },
122→        revokeToken: function(id) { return this.del('/auth/tokens/' + id); },
123→        rotateToken: function(id) { return this.post('/auth/tokens/' + id + '/rotate'); },
124→
125→        // ---- Listings ----
126→        getListings: function(params) { return this.get('/listings', params); },
127→        getListing: function(id) { return this.get('/listings/' + id); },
128→        createListing: function(data) { return this.post('/listings', data); },
129→        updateListing: function(id, data) { return this.put('/listings/' + id, data); },
130→        deleteListing: function(id) { return this.del('/listings/' + id); },
131→        publishListing: function(id) { return this.post('/listings/' + id + '/publish'); },
132→        unpublishListing: function(id) { return this.post('/listings/' + id + '/unpublish'); },
133→        bulkClose: function(ids, reason) { return this.post('/listings/bulk-close', { listing_ids: ids, reason: reason }); },
134→        getVersions: function(id) { return this.get('/listings/' + id + '/versions'); },
135→        getVersion: function(id, v) { return this.get('/listings/' + id + '/versions/' + v); },
136→        diffVersions: function(id, v1, v2) { return this.get('/listings/' + id + '/versions/' + v1 + '/diff/' + v2); },
137→
138→        // ---- Search ----
139→        getSuggestions: function(q) { return this.get('/search/suggestions', { q: q }); },
140→        getDidYouMean: function(q) { return this.get('/search/did-you-mean', { q: q }); },
141→
142→        // ---- Orders ----
143→        getOrders: function(params) { return this.get('/orders', params); },
144→        getOrder: function(id) { return this.get('/orders/' + id); },
145→        createOrder: function(data) { return this.post('/orders', data); },
146→        acceptOrder: function(id) { return this.post('/orders/' + id + '/accept'); },
147→        startOrder: function(id) { return this.post('/orders/' + id + '/start'); },
148→        completeOrder: function(id) { return this.post('/orders/' + id + '/complete'); },
149→        cancelOrder: function(id, data) { return this.post('/orders/' + id + '/cancel', data); },
150→        disputeOrder: function(id, data) { return this.post('/orders/' + id + '/dispute', data); },
151→        resolveOrder: function(id, data) { return this.post('/orders/' + id + '/resolve', data); },
152→
153→        // ---- Reviews ----
154→        getReviews: function(params) { return this.get('/reviews', params); },
155→        createReview: function(formData) { return this.upload('/reviews', formData); },
156→        updateReview: function(id, data) { return this.put('/reviews/' + id, data); },
157→        deleteReview: function(id) { return this.del('/reviews/' + id); },
158→
159→        // ---- Moderation ----
160→        getModerationQueue: function(params) { return this.get('/moderation/queue', params); },
161→        approveModeration: function(id) { return this.post('/moderation/queue/' + id + '/approve'); },
162→        rejectModeration: function(id, reason) { return this.post('/moderation/queue/' + id + '/reject', { reason: reason }); },
163→        escalateModeration: function(id) { return this.post('/moderation/queue/' + id + '/escalate'); },
164→
165→        // ---- Governance ----
166→        getQualityMetrics: function(params) { return this.get('/governance/quality-metrics', params); },
167→        getLineage: function(params) { return this.get('/governance/lineage', params); },
168→        getEvents: function(params) { return this.get('/governance/events', params); },
169→
170→        // ---- Audit ----
171→        getAuditLogs: function(params) { return this.get('/audit/logs', params); },
172→
173→        // ---- Org ----
174→        getOrgSettings: function() { return this.get('/org/settings'); },
175→        updateOrgSettings: function(data) { return this.put('/org/settings', data); },
176→
177→        // ---- Users ----
178→        getUsers: function(params) { return this.get('/users', params); },
179→        getUser: function(id) { return this.get('/users/' + id); },
180→        updateUserRoles: function(id, roles) { return this.put('/users/' + id + '/roles', { roles: roles }); },
181→        disableUser: function(id) { return this.post('/users/' + id + '/disable'); },
182→        enableUser: function(id) { return this.post('/users/' + id + '/enable'); }
183→    };
184→})();
