  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\exception\AuthException;
  7→use app\exception\BusinessException;
  8→use app\exception\NotFoundException;
  9→use app\exception\ValidationException;
 10→use app\model\Organization;
 11→use app\model\Role;
 12→use app\model\User;
 13→use app\model\UserSession;
 14→use think\facade\Session;
 15→
 16→class AuthService
 17→{
 18→    /**
 19→     * Register a new user within an organization.
 20→     */
 21→    public function register(array $data): User
 22→    {
 23→        $org = Organization::where('code', $data['organization_code'])->find();
 24→        if (!$org) {
 25→            throw new NotFoundException('Organization not found', 40401);
 26→        }
 27→
 28→        $existing = User::where('email', $data['email'])
 29→            ->where('organization_id', $org->id)
 30→            ->find();
 31→        if ($existing) {
 32→            throw new BusinessException('Email already registered in this organization', 40901, 409);
 33→        }
 34→
 35→        $user = new User();
 36→        $user->name            = $data['name'];
 37→        $user->email           = $data['email'];
 38→        $user->password_hash   = password_hash($data['password'], PASSWORD_BCRYPT);
 39→        $user->organization_id = $org->id;
 40→        $user->status          = 'active';
 41→        $user->save();
 42→
 43→        // Assign default 'user' role
 44→        $role = Role::where('slug', 'user')
 45→            ->where('org_id', $org->id)
 46→            ->find();
 47→        if ($role) {
 48→            $user->roles()->attach($role->id);
 49→        }
 50→
 51→        // Create initial session record
 52→        $session = new UserSession();
 53→        $session->user_id   = $user->id;
 54→        $session->session_id = session_id() ?: bin2hex(random_bytes(20));
 55→        $session->ip_address = request()->ip();
 56→        $session->user_agent = request()->header('User-Agent', '');
 57→        $session->expires_at = date('Y-m-d\TH:i:s\Z', strtotime('+24 hours'));
 58→        $session->save();
 59→
 60→        return $user;
 61→    }
 62→
 63→    /**
 64→     * Authenticate a user by email and password.
 65→     */
 66→    public function login(string $email, string $password, string $ip, string $userAgent): array
 67→    {
 68→        $user = User::where('email', $email)->find();
 69→        if (!$user) {
 70→            throw new AuthException('Invalid credentials', 40101);
 71→        }
 72→
 73→        if (!password_verify($password, $user->password_hash)) {
 74→            throw new AuthException('Invalid credentials', 40101);
 75→        }
 76→
 77→        if ($user->status !== 'active') {
 78→            throw new AuthException('Account is disabled', 40102);
 79→        }
 80→
 81→        $expiresAt = date('Y-m-d\TH:i:s\Z', strtotime('+24 hours'));
 82→
 83→        // Create session record
 84→        $session = new UserSession();
 85→        $session->user_id   = $user->id;
 86→        $session->session_id = session_id() ?: bin2hex(random_bytes(20));
 87→        $session->ip_address = $ip;
 88→        $session->user_agent = $userAgent;
 89→        $session->expires_at = $expiresAt;
 90→        $session->save();
 91→
 92→        // Start PHP session
 93→        Session::set('user_id', $user->id);
 94→
 95→        return [
 96→            'user'               => $user,
 97→            'session_expires_at' => $expiresAt,
 98→        ];
 99→    }
100→
101→    /**
102→     * Log out a user by destroying their session.
103→     */
104→    public function logout(int $userId, string $sessionId): void
105→    {
106→        UserSession::where('user_id', $userId)
107→            ->where('session_id', $sessionId)
108→            ->delete();
109→
110→        Session::clear();
111→    }
112→
113→    /**
114→     * Get the current authenticated user with roles.
115→     */
116→    public function getCurrentUser(int $userId): User
117→    {
118→        $user = User::with(['roles'])->find($userId);
119→        if (!$user) {
120→            throw new NotFoundException('User not found', 40401);
121→        }
122→        return $user;
123→    }
124→}
