  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\exception\BusinessException;
  7→use app\exception\ForbiddenException;
  8→use app\exception\NotFoundException;
  9→use app\exception\ValidationException;
 10→use app\model\Listing;
 11→use app\model\ListingVersion;
 12→use app\model\ModerationQueue;
 13→use app\model\SearchDictionary;
 14→use think\Collection;
 15→
 16→class ListingService
 17→{
 18→    protected ModerationService $moderationService;
 19→    protected SearchService $searchService;
 20→
 21→    public function __construct()
 22→    {
 23→        $this->moderationService = new ModerationService();
 24→        $this->searchService     = new SearchService();
 25→    }
 26→
 27→    /**
 28→     * Search listings with filters, sorting, highlighting, suggestions, and did-you-mean.
 29→     */
 30→    public function search(int $orgId, array $filters): array
 31→    {
 32→        $page    = max(1, (int) ($filters['page'] ?? 1));
 33→        $perPage = min(100, max(1, (int) ($filters['per_page'] ?? 15)));
 34→        $q       = trim($filters['q'] ?? '');
 35→        $sort    = $filters['sort'] ?? 'newest';
 36→
 37→        $query = Listing::where('organization_id', $orgId);
 38→
 39→        // Text search
 40→        if ($q !== '') {
 41→            $query->where(function ($subQuery) use ($q) {
 42→                $likeQ = '%' . $q . '%';
 43→                $subQuery->whereLike('title', $likeQ)
 44→                    ->whereOrLike('description', $likeQ)
 45→                    ->whereOr('tags', 'like', $likeQ);
 46→            });
 47→        }
 48→
 49→        // Status filter
 50→        if (!empty($filters['status'])) {
 51→            $query->where('status', $filters['status']);
 52→        }
 53→
 54→        // Vehicle type filter
 55→        if (!empty($filters['vehicle_type'])) {
 56→            $query->where('vehicle_type', $filters['vehicle_type']);
 57→        }
 58→
 59→        // Rider count range
 60→        if (isset($filters['rider_count_min'])) {
 61→            $query->where('rider_count', '>=', (int) $filters['rider_count_min']);
 62→        }
 63→        if (isset($filters['rider_count_max'])) {
 64→            $query->where('rider_count', '<=', (int) $filters['rider_count_max']);
 65→        }
 66→
 67→        // Sorting
 68→        switch ($sort) {
 69→            case 'most_discussed':
 70→                $query->order('comment_count', 'desc');
 71→                break;
 72→            case 'most_popular':
 73→                $query->orderRaw('(favorite_count + view_count) DESC');
 74→                break;
 75→            case 'newest':
 76→            default:
 77→                $query->order('created_at', 'desc');
 78→                break;
 79→        }
 80→
 81→        $total    = $query->count();
 82→        $listings = $query->page($page, $perPage)->select();
 83→        $lastPage = (int) ceil($total / $perPage);
 84→
 85→        // Build highlight data
 86→        $highlights = [];
 87→        if ($q !== '' && $listings->count() > 0) {
 88→            $terms = preg_split('/\s+/', $q);
 89→            foreach ($listings as $listing) {
 90→                $highlighted = [];
 91→                foreach (['title', 'description'] as $field) {
 92→                    $value = $listing->$field ?? '';
 93→                    foreach ($terms as $term) {
 94→                        $value = preg_replace(
 95→                            '/(' . preg_quote($term, '/') . ')/i',
 96→                            '<em>$1</em>',
 97→                            $value
 98→                        );
 99→                    }
100→                    $highlighted[$field] = $value;
101→                }
102→                $highlights[$listing->id] = $highlighted;
103→            }
104→        }
105→
106→        // Fallback: recent active if no results for a query
107→        $recentActive = [];
108→        if ($q !== '' && $listings->count() === 0) {
109→            $recentActive = Listing::where('organization_id', $orgId)
110→                ->where('status', 'active')
111→                ->order('created_at', 'desc')
112→                ->limit(10)
113→                ->select()
114→                ->toArray();
115→        }
116→
117→        // Suggestions and did-you-mean
118→        $suggestions = [];
119→        $didYouMean  = null;
120→        if ($q !== '') {
121→            $suggestions = $this->searchService->getSuggestions($orgId, $q);
122→            $didYouMean  = $this->searchService->getDidYouMean($orgId, $q);
123→        }
124→
125→        return [
126→            'listings'      => $listings->toArray(),
127→            'highlights'    => $highlights,
128→            'recent_active' => $recentActive,
129→            'suggestions'   => $suggestions,
130→            'did_you_mean'  => $didYouMean,
