190→    /**
191→     * Update an existing listing.
192→     */
193→    public function update(int $listingId, int $userId, array $data): Listing
194→    {
195→        $listing = Listing::find($listingId);
196→        if (!$listing) {
197→            throw new NotFoundException('Listing not found');
198→        }
199→        if ((int) $listing->user_id !== $userId) {
200→            throw new ForbiddenException('You do not own this listing');
201→        }
202→        if (!in_array($listing->status, ['draft', 'active'])) {
203→            throw new BusinessException('Listing cannot be edited in its current status', 40901, 409);
204→        }
205→
206→        $oldSnapshot = $this->takeSnapshot($listing);
207→
208→        // Apply updates
209→        $updatableFields = [
210→            'title', 'description', 'pickup_address', 'dropoff_address',
211→            'rider_count', 'vehicle_type', 'baggage_notes',
212→            'time_window_start', 'time_window_end', 'tags',
213→        ];
214→        foreach ($updatableFields as $field) {
215→            if (array_key_exists($field, $data)) {
216→                if ($field === 'tags' && is_array($data[$field])) {
217→                    $listing->$field = json_encode($data[$field]);
218→                } elseif ($field === 'rider_count') {
219→                    $listing->$field = (int) $data[$field];
220→                } else {
221→                    $listing->$field = $data[$field];
222→                }
223→            }
224→        }
225→
226→        $listing->version = (int) $listing->version + 1;
227→        $listing->save();
228→
229→        // Build change summary
230→        $newSnapshot = $this->takeSnapshot($listing);
231→        $changeSummary = $this->buildChangeSummary($oldSnapshot, $newSnapshot);
232→        $this->createVersionSnapshot($listing, $changeSummary);
233→
234→        // Sensitive word check
235→        $textToCheck = $listing->title . ' ' . ($listing->description ?? '');
236→        $checkResult = $this->moderationService->checkSensitiveWords($textToCheck);
237→        if ($checkResult && $checkResult['matched']) {
238→            $listing->status = 'draft';
239→            $listing->save();
240→
241→            $this->moderationService->flagItem(
242→                (int) $listing->organization_id,
243→                'listing',
244→                $listing->id,
245→                'sensitive_words',
246→                'Matched words: ' . implode(', ', $checkResult['words']),
247→                null
248→            );
249→        }
250→
251→        return $listing;
252→    }
