332→    /**
333→     * Bulk close active listings with no matched orders (admin only).
334→     */
335→    public function bulkClose(int $orgId, array $listingIds, string $reason): array
336→    {
337→        $closed = [];
338→        $failed = [];
339→
340→        foreach ($listingIds as $id) {
341→            $listing = Listing::where('id', $id)
342→                ->where('organization_id', $orgId)
343→                ->find();
344→
345→            if (!$listing) {
346→                $failed[] = ['id' => $id, 'reason' => 'Listing not found'];
347→                continue;
348→            }
349→
350→            if ($listing->status !== 'active') {
351→                $failed[] = ['id' => $id, 'reason' => 'Listing is not active (status: ' . $listing->status . ')'];
352→                continue;
353→            }
354→
355→            // Check for matched orders
356→            $hasMatchedOrders = \app\model\Order::where('listing_id', $id)
357→                ->whereIn('status', ['pending_match', 'accepted', 'in_progress'])
358→                ->count();
359→
360→            if ($hasMatchedOrders > 0) {
361→                $failed[] = ['id' => $id, 'reason' => 'Listing has active orders'];
362→                continue;
363→            }
364→
365→            $listing->status       = 'closed';
366→            $listing->close_reason = $reason;
367→            $listing->save();
368→            $closed[] = $id;
369→        }
370→
371→        return [
372→            'closed' => $closed,
373→            'failed' => $failed,
374→        ];
375→    }
