408→    /**
409→     * Diff two versions of a listing, returning field-level changes.
410→     */
411→    public function diffVersions(int $listingId, int $v1, int $v2): array
412→    {
413→        $version1 = $this->getVersion($listingId, $v1);
414→        $version2 = $this->getVersion($listingId, $v2);
415→
416→        $snapshot1 = is_string($version1->snapshot) ? json_decode($version1->snapshot, true) : ($version1->snapshot ?? []);
417→        $snapshot2 = is_string($version2->snapshot) ? json_decode($version2->snapshot, true) : ($version2->snapshot ?? []);
418→
419→        $allKeys = array_unique(array_merge(array_keys($snapshot1), array_keys($snapshot2)));
420→        $changes = [];
421→
422→        foreach ($allKeys as $field) {
423→            $oldVal = $snapshot1[$field] ?? null;
424→            $newVal = $snapshot2[$field] ?? null;
425→
426→            if ($oldVal !== $newVal) {
427→                $changes[] = [
428→                    'field'     => $field,
429→                    'old_value' => $oldVal,
430→                    'new_value' => $newVal,
431→                ];
432→            }
433→        }
434→
435→        return $changes;
436→    }
