438→    // ---- Private helpers ----
439→
440→    private function takeSnapshot(Listing $listing): array
441→    {
442→        return [
443→            'title'             => $listing->title,
444→            'description'       => $listing->description,
445→            'pickup_address'    => $listing->pickup_address,
446→            'dropoff_address'   => $listing->dropoff_address,
447→            'rider_count'       => $listing->rider_count,
448→            'vehicle_type'      => $listing->vehicle_type,
449→            'baggage_notes'     => $listing->baggage_notes,
450→            'time_window_start' => $listing->time_window_start,
451→            'time_window_end'   => $listing->time_window_end,
452→            'tags'              => $listing->tags,
453→            'status'            => $listing->status,
454→        ];
455→    }
456→
457→    private function createVersionSnapshot(Listing $listing, string $changeSummary): void
458→    {
459→        $version = new ListingVersion();
460→        $version->listing_id     = $listing->id;
461→        $version->version        = (int) $listing->version;
462→        $version->snapshot       = json_encode($this->takeSnapshot($listing));
463→        $version->change_summary = $changeSummary;
464→        $version->created_by     = (int) $listing->user_id;
465→        $version->save();
466→    }
467→
468→    private function buildChangeSummary(array $old, array $new): string
469→    {
470→        $changes = [];
471→        foreach ($new as $key => $value) {
472→            $oldVal = $old[$key] ?? null;
473→            if ($value !== $oldVal) {
474→                $changes[] = $key;
475→            }
476→        }
477→
478→        if (empty($changes)) {
479→            return 'No changes';
480→        }
481→
482→        return 'Updated: ' . implode(', ', $changes);
483→    }
484→}
