202→    /**
203→     * Cancel an order with strict business rules.
204→     */
205→    public function cancel(int $orderId, int $userId, ?string $reasonCode, ?string $reasonText): Order
206→    {
207→        $order = $this->findOrderOrFail($orderId);
208→        $this->verifyParty($order, $userId);
209→
210→        // Rule 2: Cannot cancel in_progress
211→        if ($order->status === 'in_progress') {
212→            throw new BusinessException(
213→                'Cancellation is not allowed once a trip is in progress.',
214→                40901,
215→                409
216→            );
217→        }
218→
219→        // Must be in a cancellable state
220→        if (!in_array($order->status, ['pending_match', 'accepted'])) {
221→            throw new BusinessException(
222→                'Order cannot be cancelled in its current status',
223→                40901,
224→                409
225→            );
226→        }
227→
228→        // Rule 4: Accepted order cancellation rules
229→        if ($order->status === 'accepted') {
230→            $acceptedAt       = strtotime($order->accepted_at);
231→            $fiveMinutesLater = $acceptedAt + (5 * 60);
232→            $now              = time();
233→
234→            if ($now > $fiveMinutesLater) {
235→                // Past 5 minutes: reason_code required
236→                if (empty($reasonCode)) {
237→                    throw new ValidationException(
238→                        'Cancellation reason is required after the free cancellation window',
239→                        ['reason_code' => 'Reason code is required for late cancellations']
240→                    );
241→                }
242→
243→                // If OTHER, reason_text is required
244→                if ($reasonCode === 'OTHER' && empty($reasonText)) {
245→                    throw new ValidationException(
246→                        'Reason text is required when reason code is OTHER',
247→                        ['reason_text' => 'Please provide details for your cancellation reason']
248→                    );
249→                }
250→            }
251→            // Within 5 minutes: free cancel, no reason required
252→        }
253→
254→        // Rule 5: Apply cancellation
255→        $oldStatus = $order->status;
256→        $order->status             = 'cancelled';
257→        $order->canceled_at        = date('Y-m-d\TH:i:s\Z');
258→        $order->cancel_reason_code = $reasonCode;
259→        $order->cancel_reason_text = $reasonText;
260→        $order->save();
261→
262→        // Restore listing to active
263→        $listing = Listing::find($order->listing_id);
264→        if ($listing) {
265→            $listing->status = 'active';
266→            $listing->save();
267→        }
268→
269→        // Rule 6: Record audit log
270→        $this->auditService->log(
271→            (int) $order->organization_id,
272→            $userId,
273→            'order.cancel',
274→            'order',
275→            $order->id,
276→            ['status' => $oldStatus],
277→            ['status' => 'cancelled', 'reason_code' => $reasonCode, 'reason_text' => $reasonText]
278→        );
279→
280→        return $order;
281→    }
