335→    /**
336→     * Resolve a disputed order (admin only, checked at route level).
337→     */
338→    public function resolve(int $orderId, string $resolution, string $outcome): Order
339→    {
340→        $order = $this->findOrderOrFail($orderId);
341→
342→        if ($order->status !== 'disputed') {
343→            throw new BusinessException(
344→                'Only disputed orders can be resolved',
345→                40901,
346→                409
347→            );
348→        }
349→
350→        $oldStatus = $order->status;
351→        $order->status             = 'resolved';
352→        $order->resolved_at        = date('Y-m-d\TH:i:s\Z');
353→        $order->resolution_notes   = $resolution;
354→        $order->resolution_outcome = $outcome;
355→        $order->save();
356→
357→        // Update listing status
358→        $listing = Listing::find($order->listing_id);
359→        if ($listing) {
360→            $listing->status = 'resolved';
361→            $listing->save();
362→        }
363→
364→        $this->auditService->log(
365→            (int) $order->organization_id,
366→            (int) request()->user->id,
367→            'order.resolve',
368→            'order',
369→            $order->id,
370→            ['status' => $oldStatus],
371→            ['status' => 'resolved', 'outcome' => $outcome]
372→        );
373→
374→        return $order;
375→    }
376→
377→    /**
378→     * Expire all pending orders that have passed their 30-minute window.
379→     */
380→    public function expirePendingOrders(): int
381→    {
382→        $cutoff = date('Y-m-d\TH:i:s\Z', strtotime('-30 minutes'));
383→
384→        $expiredOrders = Order::where('status', 'pending_match')
385→            ->where('created_at', '<', $cutoff)
386→            ->select();
387→
388→        $count = 0;
389→        foreach ($expiredOrders as $order) {
390→            $order->status = 'expired';
391→            $order->save();
392→
393→            // Restore listing to active
394→            $listing = Listing::find($order->listing_id);
395→            if ($listing && $listing->status === 'matched') {
396→                $listing->status = 'active';
397→                $listing->save();
398→            }
399→
400→            $count++;
401→        }
402→
403→        return $count;
404→    }
405→
406→    // ---- Private helpers ----
407→
408→    private function findOrderOrFail(int $orderId): Order
409→    {
410→        $order = Order::find($orderId);
411→        if (!$order) {
412→            throw new NotFoundException('Order not found');
413→        }
414→        return $order;
415→    }
416→
417→    private function verifyParty(Order $order, int $userId): void
418→    {
419→        if ((int) $order->passenger_id !== $userId && (int) $order->driver_id !== $userId) {
420→            throw new ForbiddenException('You are not a party to this order');
421→        }
422→    }
423→}
