  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\exception\BusinessException;
  7→use app\exception\ForbiddenException;
  8→use app\exception\NotFoundException;
  9→use app\model\Order;
 10→use app\model\Review;
 11→
 12→class ReviewService
 13→{
 14→    protected ModerationService $moderationService;
 15→    protected CredibilityService $credibilityService;
 16→    protected MediaService $mediaService;
 17→    protected AuditService $auditService;
 18→
 19→    public function __construct()
 20→    {
 21→        $this->moderationService   = new ModerationService();
 22→        $this->credibilityService  = new CredibilityService();
 23→        $this->mediaService        = new MediaService();
 24→        $this->auditService        = new AuditService();
 25→    }
 26→
 27→    /**
 28→     * List reviews with filters and pagination, including media with signed URLs.
 29→     */
 30→    public function list(int $orgId, array $filters): array
 31→    {
 32→        $page    = max(1, (int) ($filters['page'] ?? 1));
 33→        $perPage = min(100, max(1, (int) ($filters['per_page'] ?? 15)));
 34→
 35→        $query = Review::where('organization_id', $orgId);
 36→
 37→        if (!empty($filters['listing_id'])) {
 38→            $query->where('listing_id', (int) $filters['listing_id']);
 39→        }
 40→        if (!empty($filters['user_id'])) {
 41→            $query->where('user_id', (int) $filters['user_id']);
 42→        }
 43→        if (!empty($filters['order_id'])) {
 44→            $query->where('order_id', (int) $filters['order_id']);
 45→        }
 46→
 47→        $query->order('created_at', 'desc');
 48→
 49→        $total   = $query->count();
 50→        $reviews = $query->page($page, $perPage)->with(['media'])->select();
 51→        $lastPage = (int) ceil($total / $perPage);
 52→
 53→        // Attach signed URLs to media
 54→        $reviewsArray = $reviews->toArray();
 55→        foreach ($reviewsArray as &$review) {
 56→            if (!empty($review['media'])) {
 57→                foreach ($review['media'] as &$media) {
 58→                    $media['signed_url'] = $this->mediaService->generateSignedUrl((int) $media['id']);
 59→                }
 60→                unset($media);
 61→            }
 62→        }
 63→        unset($review);
 64→
 65→        return [
 66→            'reviews' => $reviewsArray,
 67→            'meta'    => [
 68→                'total'     => $total,
 69→                'page'      => $page,
 70→                'per_page'  => $perPage,
 71→                'last_page' => $lastPage,
 72→            ],
 73→        ];
 74→    }
 75→
 76→    /**
 77→     * Create a review for a completed order.
 78→     */
 79→    public function create(int $orgId, int $userId, array $data, array $files = []): Review
 80→    {
 81→        $orderId = (int) $data['order_id'];
 82→
 83→        $order = Order::where('id', $orderId)
 84→            ->where('organization_id', $orgId)
 85→            ->find();
 86→
 87→        if (!$order) {
 88→            throw new NotFoundException('Order not found');
 89→        }
 90→
 91→        if ($order->status !== 'completed') {
 92→            throw new BusinessException('Reviews can only be created for completed orders', 40901, 409);
 93→        }
 94→
 95→        if ((int) $order->passenger_id !== $userId && (int) $order->driver_id !== $userId) {
 96→            throw new ForbiddenException('You are not a party to this order');
 97→        }
 98→
 99→        // Check for existing review by this user for this order
100→        $existingReview = Review::where('order_id', $orderId)
101→            ->where('user_id', $userId)
102→            ->find();
103→
104→        if ($existingReview) {
105→            throw new BusinessException('You have already reviewed this order', 40901, 409);
106→        }
107→
108→        // Check for duplicate text
109→        $isDuplicate = $this->moderationService->checkDuplicateText($userId, $data['text'], $orgId);
110→
111→        // Compute credibility score
112→        $credibilityScore = $this->credibilityService->compute($userId, $orderId, $orgId);
113→
114→        // Run sensitive-word check
115→        $sensitiveCheck = $this->moderationService->checkSensitiveWords($data['text']);
116→
117→        $needsModeration = $isDuplicate || ($sensitiveCheck && $sensitiveCheck['matched']);
118→
119→        $review = new Review();
120→        $review->organization_id   = $orgId;
121→        $review->user_id           = $userId;
122→        $review->order_id          = $orderId;
123→        $review->listing_id        = (int) $order->listing_id;
124→        $review->rating            = (int) $data['rating'];
125→        $review->text              = $data['text'];
126→        $review->credibility_score = $credibilityScore;
127→        $review->status            = $needsModeration ? 'pending' : 'published';
128→        $review->save();
129→
130→        // Handle media uploads
131→        foreach ($files as $file) {
132→            $this->mediaService->upload($orgId, $userId, $file, 'review', $review->id);
133→        }
134→
135→        // If flagged, add to moderation queue
136→        if ($needsModeration) {
137→            $flagReason = '';
138→            $flagDetails = '';
139→
140→            if ($isDuplicate) {
141→                $flagReason  = 'duplicate_text';
142→                $flagDetails = 'Review text is too similar to a recent review by this user';
143→            }
144→
145→            if ($sensitiveCheck && $sensitiveCheck['matched']) {
146→                $flagReason  = $flagReason ? $flagReason . ',sensitive_words' : 'sensitive_words';
147→                $flagDetails .= ($flagDetails ? '; ' : '') . 'Matched words: ' . implode(', ', $sensitiveCheck['words']);
148→            }
149→
150→            $this->moderationService->flagItem(
151→                $orgId,
152→                'review',
153→                $review->id,
154→                $flagReason,
155→                $flagDetails,
156→                $credibilityScore
157→            );
158→        }
159→
160→        // Record audit log
161→        $this->auditService->log(
162→            $orgId,
163→            $userId,
164→            'review.create',
165→            'review',
166→            $review->id,
167→            null,
168→            ['rating' => $review->rating, 'status' => $review->status]
169→        );
170→
171→        return $review;
172→    }
173→
174→    /**
175→     * Update a review (owner only, not yet moderated).
176→     */
177→    public function update(int $reviewId, int $userId, array $data): Review
178→    {
179→        $review = Review::find($reviewId);
180→        if (!$review) {
181→            throw new NotFoundException('Review not found');
182→        }
183→        if ((int) $review->user_id !== $userId) {
184→            throw new ForbiddenException('You do not own this review');
185→        }
186→        if ($review->status !== 'published') {
187→            throw new BusinessException('Only published reviews can be edited', 40901, 409);
188→        }
189→
190→        $oldValues = ['rating' => $review->rating, 'text' => $review->text];
191→
192→        if (isset($data['rating'])) {
193→            $review->rating = (int) $data['rating'];
194→        }
195→        if (isset($data['text'])) {
196→            $review->text = $data['text'];
197→        }
198→
199→        // Re-run checks
200→        $sensitiveCheck = $this->moderationService->checkSensitiveWords($review->text);
201→        $isDuplicate    = $this->moderationService->checkDuplicateText($userId, $review->text, (int) $review->organization_id);
202→
203→        if (($sensitiveCheck && $sensitiveCheck['matched']) || $isDuplicate) {
204→            $review->status = 'pending';
205→
206→            $flagReason  = $isDuplicate ? 'duplicate_text' : '';
207→            $flagDetails = $isDuplicate ? 'Updated review text is similar to a recent review' : '';
208→
209→            if ($sensitiveCheck && $sensitiveCheck['matched']) {
210→                $flagReason  = $flagReason ? $flagReason . ',sensitive_words' : 'sensitive_words';
211→                $flagDetails .= ($flagDetails ? '; ' : '') . 'Matched words: ' . implode(', ', $sensitiveCheck['words']);
212→            }
213→
214→            $this->moderationService->flagItem(
215→                (int) $review->organization_id,
216→                'review',
217→                $review->id,
218→                $flagReason,
219→                $flagDetails,
220→                $review->credibility_score
221→            );
222→        }
223→
224→        $review->save();
225→
226→        return $review;
227→    }
228→
229→    /**
230→     * Delete a review (owner only).
231→     */
232→    public function destroy(int $reviewId, int $userId): void
233→    {
234→        $review = Review::find($reviewId);
235→        if (!$review) {
236→            throw new NotFoundException('Review not found');
237→        }
238→        if ((int) $review->user_id !== $userId) {
239→            throw new ForbiddenException('You do not own this review');
240→        }
241→
242→        $review->delete();
243→    }
244→}
