  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\service;
  5→
  6→use app\exception\BusinessException;
  7→use app\exception\NotFoundException;
  8→use app\exception\ValidationException;
  9→use app\model\Media;
 10→use think\facade\Filesystem;
 11→
 12→class MediaService
 13→{
 14→    /**
 15→     * Allowed MIME types and size limits.
 16→     */
 17→    private const PHOTO_MIMES    = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
 18→    private const VIDEO_MIMES    = ['video/mp4', 'video/webm'];
 19→    private const PHOTO_MAX_SIZE = 5 * 1024 * 1024;    // 5MB
 20→    private const VIDEO_MAX_SIZE = 50 * 1024 * 1024;   // 50MB
 21→    private const MAX_FILES_PER_PARENT = 5;
 22→
 23→    /**
 24→     * Upload a file, validate, store, and create a Media record.
 25→     */
 26→    public function upload(int $orgId, int $userId, $file, string $parentType, int $parentId): Media
 27→    {
 28→        // Get file info
 29→        $mimeType = $file->getMime();
 30→        $fileSize = $file->getSize();
 31→        $ext      = strtolower($file->extension());
 32→
 33→        // Determine media type and validate
 34→        $isPhoto = in_array($mimeType, self::PHOTO_MIMES, true);
 35→        $isVideo = in_array($mimeType, self::VIDEO_MIMES, true);
 36→
 37→        if (!$isPhoto && !$isVideo) {
 38→            throw new ValidationException('Unsupported file type', [
 39→                'file' => 'Allowed types: jpeg, png, gif, webp, mp4, webm',
 40→            ]);
 41→        }
 42→
 43→        if ($isPhoto && $fileSize > self::PHOTO_MAX_SIZE) {
 44→            throw new ValidationException('File too large', [
 45→                'file' => 'Photos must be under 5MB',
 46→            ]);
 47→        }
 48→
 49→        if ($isVideo && $fileSize > self::VIDEO_MAX_SIZE) {
 50→            throw new ValidationException('File too large', [
 51→                'file' => 'Videos must be under 50MB',
 52→            ]);
 53→        }
 54→
 55→        // Check max files per parent
 56→        $existingCount = Media::where('parent_type', $parentType)
 57→            ->where('parent_id', $parentId)
 58→            ->count();
 59→
 60→        if ($existingCount >= self::MAX_FILES_PER_PARENT) {
 61→            throw new BusinessException(
 62→                'Maximum of ' . self::MAX_FILES_PER_PARENT . ' files per item',
 63→                40901,
 64→                409
 65→            );
 66→        }
 67→
 68→        // Generate UUID filename
 69→        $uuid     = $this->generateUuid();
 70→        $filename = $uuid . '.' . $ext;
 71→
 72→        // Build storage path
 73→        $datePath   = date('Y/m/d');
 74→        $storagePath = "{$orgId}/{$datePath}";
 75→        $fullPath    = $storagePath . '/' . $filename;
 76→
 77→        // Compute SHA-256 hash
 78→        $tempPath = $file->getPathname();
 79→        $fileHash = hash_file('sha256', $tempPath);
 80→
 81→        // Check for duplicate hash (same user, 30 days)
 82→        $thirtyDaysAgo = date('Y-m-d\TH:i:s\Z', strtotime('-30 days'));
 83→        $duplicate = Media::where('user_id', $userId)
 84→            ->where('file_hash', $fileHash)
 85→            ->where('created_at', '>', $thirtyDaysAgo)
 86→            ->find();
 87→
 88→        if ($duplicate) {
 89→            throw new BusinessException('Duplicate file detected', 40901, 409);
 90→        }
 91→
 92→        // Store file to disk
 93→        $uploadDir = runtime_path('storage') . $storagePath;
 94→        if (!is_dir($uploadDir)) {
 95→            mkdir($uploadDir, 0755, true);
 96→        }
 97→        $file->move($uploadDir, $filename);
 98→        $diskPath = $uploadDir . '/' . $filename;
 99→
100→        // Apply watermark if enabled and file is a photo
101→        if ($isPhoto && env('MEDIA_WATERMARK_ENABLED', false)) {
102→            $this->applyWatermark($diskPath, $mimeType);
103→        }
104→
105→        // Create Media record
106→        $media = new Media();
107→        $media->organization_id = $orgId;
108→        $media->user_id         = $userId;
109→        $media->parent_type     = $parentType;
110→        $media->parent_id       = $parentId;
111→        $media->file_path       = $fullPath;
112→        $media->file_name       = $filename;
113→        $media->mime_type       = $mimeType;
114→        $media->file_size       = $fileSize;
115→        $media->file_hash       = $fileHash;
116→        $media->media_type      = $isPhoto ? 'photo' : 'video';
117→        $media->save();
118→
119→        return $media;
120→    }
121→
122→    /**
123→     * Generate a signed URL for a media file.
124→     */
125→    public function generateSignedUrl(int $mediaId, ?int $expiryMinutes = null): string
126→    {
127→        if ($expiryMinutes === null) {
128→            $expiryMinutes = (int) env('MEDIA_URL_EXPIRY_MINUTES', 10);
129→        }
130→
131→        $expires   = time() + ($expiryMinutes * 60);
132→        $secret    = (string) env('MEDIA_SIGN_SECRET', '');
133→        $signature = hash_hmac('sha256', $mediaId . $expires, $secret);
134→
135→        return "/api/media/{$mediaId}?signature={$signature}&expires={$expires}";
136→    }
137→
138→    /**
139→     * Serve a media file (return path and mime for streaming).
140→     */
141→    public function serve(int $mediaId): array
142→    {
143→        $media = Media::find($mediaId);
144→        if (!$media) {
145→            throw new NotFoundException('Media not found');
146→        }
147→
148→        $diskPath = runtime_path('storage') . $media->file_path;
149→
150→        return [
151→            'file_path' => $diskPath,
152→            'mime_type' => $media->mime_type,
153→        ];
154→    }
155→
156→    /**
157→     * Generate a 200x200 thumbnail for a photo.
158→     */
159→    public function generateThumbnail(int $mediaId): string
160→    {
161→        $media = Media::find($mediaId);
162→        if (!$media) {
163→            throw new NotFoundException('Media not found');
164→        }
165→
166→        if ($media->media_type !== 'photo') {
167→            throw new BusinessException('Thumbnails can only be generated for photos', 40901);
168→        }
169→
170→        $sourcePath = runtime_path('storage') . $media->file_path;
171→        $thumbDir   = dirname($sourcePath) . '/thumbnails';
172→        $thumbPath  = $thumbDir . '/' . $media->file_name;
173→
174→        // Return cached thumbnail if it exists
175→        if (file_exists($thumbPath)) {
176→            return $thumbPath;
177→        }
178→
179→        if (!is_dir($thumbDir)) {
180→            mkdir($thumbDir, 0755, true);
181→        }
182→
183→        // Load source image
184→        $sourceImage = $this->loadImage($sourcePath, $media->mime_type);
185→        if (!$sourceImage) {
186→            throw new BusinessException('Failed to process image', 40901);
187→        }
188→
189→        $origWidth  = imagesx($sourceImage);
190→        $origHeight = imagesy($sourceImage);
191→
192→        // Create 200x200 thumbnail with aspect ratio preservation (crop to fill)
193→        $thumbWidth  = 200;
194→        $thumbHeight = 200;
195→
196→        $ratio  = max($thumbWidth / $origWidth, $thumbHeight / $origHeight);
197→        $srcW   = (int) round($thumbWidth / $ratio);
198→        $srcH   = (int) round($thumbHeight / $ratio);
199→        $srcX   = (int) round(($origWidth - $srcW) / 2);
200→        $srcY   = (int) round(($origHeight - $srcH) / 2);
201→
202→        $thumbnail = imagecreatetruecolor($thumbWidth, $thumbHeight);
203→
204→        // Preserve transparency for PNG/GIF/WebP
205→        if (in_array($media->mime_type, ['image/png', 'image/gif', 'image/webp'])) {
206→            imagealphablending($thumbnail, false);
207→            imagesavealpha($thumbnail, true);
208→            $transparent = imagecolorallocatealpha($thumbnail, 0, 0, 0, 127);
209→            imagefill($thumbnail, 0, 0, $transparent);
210→        }
211→
212→        imagecopyresampled(
213→            $thumbnail,
214→            $sourceImage,
215→            0, 0,
216→            $srcX, $srcY,
217→            $thumbWidth, $thumbHeight,
218→            $srcW, $srcH
219→        );
220→
221→        // Save thumbnail
222→        $this->saveImage($thumbnail, $thumbPath, $media->mime_type);
223→
224→        imagedestroy($sourceImage);
225→        imagedestroy($thumbnail);
226→
227→        return $thumbPath;
228→    }
229→
230→    /**
231→     * Apply a watermark to a photo using GD.
232→     */
233→    public function applyWatermark(string $filePath, string $mimeType): void
234→    {
235→        $watermarkPath = (string) env('MEDIA_WATERMARK_IMAGE', '');
236→        if ($watermarkPath === '' || !file_exists($watermarkPath)) {
237→            return;
238→        }
239→
240→        $image = $this->loadImage($filePath, $mimeType);
241→        if (!$image) {
242→            return;
243→        }
244→
245→        $watermark = imagecreatefrompng($watermarkPath);
246→        if (!$watermark) {
247→            imagedestroy($image);
248→            return;
249→        }
250→
251→        $imgWidth  = imagesx($image);
252→        $imgHeight = imagesy($image);
253→        $wmWidth   = imagesx($watermark);
254→        $wmHeight  = imagesy($watermark);
255→
256→        // Position at bottom-right with 10px padding
257→        $destX = $imgWidth - $wmWidth - 10;
258→        $destY = $imgHeight - $wmHeight - 10;
259→
260→        // Ensure non-negative positioning
261→        $destX = max(0, $destX);
262→        $destY = max(0, $destY);
263→
264→        // Enable alpha blending and overlay watermark
265→        imagealphablending($image, true);
266→        imagecopy($image, $watermark, $destX, $destY, 0, 0, $wmWidth, $wmHeight);
267→
268→        // Save back
269→        $this->saveImage($image, $filePath, $mimeType);
270→
271→        imagedestroy($image);
272→        imagedestroy($watermark);
273→    }
274→
275→    // ---- Private helpers ----
276→
277→    private function generateUuid(): string
278→    {
279→        $data    = random_bytes(16);
280→        $data[6] = chr(ord($data[6]) & 0x0f | 0x40); // UUID v4
281→        $data[8] = chr(ord($data[8]) & 0x3f | 0x80);
282→
283→        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($data), 4));
284→    }
285→
286→    private function loadImage(string $path, string $mimeType)
287→    {
288→        switch ($mimeType) {
289→            case 'image/jpeg':
290→                return imagecreatefromjpeg($path);
291→            case 'image/png':
292→                return imagecreatefrompng($path);
293→            case 'image/gif':
294→                return imagecreatefromgif($path);
295→            case 'image/webp':
296→                return imagecreatefromwebp($path);
297→            default:
298→                return null;
299→        }
300→    }
301→
302→    private function saveImage($image, string $path, string $mimeType): void
303→    {
304→        switch ($mimeType) {
305→            case 'image/jpeg':
306→                imagejpeg($image, $path, 90);
307→                break;
308→            case 'image/png':
309→                imagepng($image, $path, 6);
310→                break;
311→            case 'image/gif':
312→                imagegif($image, $path);
313→                break;
314→            case 'image/webp':
315→                imagewebp($image, $path, 90);
316→                break;
317→        }
318→    }
319→}
