  4→namespace app\service;
  5→
  6→use app\model\AuditLog;
  7→
  8→class AuditService
  9→{
 10→    /**
 11→     * Fields to strip from audit log old/new values for security.
 12→     */
 13→    private const SENSITIVE_FIELDS = ['password', 'password_hash', 'token_hash', 'password_confirmation'];
 14→
 15→    /**
 16→     * Create an audit log entry.
 17→     */
 18→    public function log(
 19→        int $orgId,
 20→        int $userId,
 21→        string $action,
 22→        string $resourceType,
 23→        ?int $resourceId,
 24→        $oldValue = null,
 25→        $newValue = null
 26→    ): void {
 27→        $entry = new AuditLog();
 28→        $entry->organization_id = $orgId;
 29→        $entry->user_id         = $userId;
 30→        $entry->action          = $action;
 31→        $entry->resource_type   = $resourceType;
 32→        $entry->resource_id     = $resourceId;
 33→        $entry->old_value       = $oldValue !== null ? json_encode($this->sanitize($oldValue)) : null;
 34→        $entry->new_value       = $newValue !== null ? json_encode($this->sanitize($newValue)) : null;
 35→        $entry->ip_address      = request()->ip();
 36→        $entry->save();
 37→    }
 38→
 39→    /**
 40→     * Query audit logs with filters and pagination.
 41→     */
 42→    public function query(int $orgId, array $filters, bool $unmask = false): array
 43→    {
 44→        $page    = max(1, (int) ($filters['page'] ?? 1));
 45→        $perPage = min(100, max(1, (int) ($filters['per_page'] ?? 15)));
 46→
 47→        $query = AuditLog::where('organization_id', $orgId);
 48→
 49→        if (!empty($filters['user_id'])) {
 50→            $query->where('user_id', (int) $filters['user_id']);
 51→        }
 52→        if (!empty($filters['action'])) {
 53→            $query->where('action', $filters['action']);
 54→        }
 55→        if (!empty($filters['resource_type'])) {
 56→            $query->where('resource_type', $filters['resource_type']);
 57→        }
 58→        if (!empty($filters['from_date'])) {
 59→            $query->where('created_at', '>=', $filters['from_date']);
 60→        }
 61→        if (!empty($filters['to_date'])) {
 62→            $query->where('created_at', '<=', $filters['to_date']);
 63→        }
 64→
 65→        $query->order('created_at', 'desc');
 66→
 67→        $total    = $query->count();
 68→        $logs     = $query->page($page, $perPage)->select();
 69→        $lastPage = (int) ceil($total / $perPage);
 70→
 71→        $logsArray = [];
 72→        foreach ($logs as $log) {
 73→            if ($unmask) {
 74→                $logsArray[] = $log->toUnmaskedArray();
 75→            } else {
 76→                $logsArray[] = $log->toMaskedArray();
 77→            }
 78→        }
 79→
 80→        return [
 81→            'audit_logs' => $logsArray,
 82→            'meta'       => [
 83→                'total'     => $total,
 84→                'page'      => $page,
