 91→    /**
 92→     * Strip sensitive fields from values before storing.
 93→     */
 94→    private function sanitize($value): array
 95→    {
 96→        if (!is_array($value)) {
 97→            return [];
 98→        }
 99→
100→        $sanitized = $value;
101→        foreach (self::SENSITIVE_FIELDS as $field) {
102→            if (array_key_exists($field, $sanitized)) {
103→                unset($sanitized[$field]);
104→            }
105→        }
106→
107→        return $sanitized;
108→    }
109→}
