 1→<?php
 2→declare(strict_types=1);
 3→
 4→namespace app\service;
 5→
 6→use app\model\SearchDictionary;
 7→
 8→class SearchService
 9→{
10→    /**
11→     * Get autocomplete suggestions from the search dictionary.
12→     */
13→    public function getSuggestions(int $orgId, string $query): array
14→    {
15→        $query = trim($query);
16→        if ($query === '') {
17→            return [];
18→        }
19→
20→        return SearchDictionary::where('organization_id', $orgId)
21→            ->whereLike('word', $query . '%')
22→            ->order('frequency', 'desc')
23→            ->limit(10)
24→            ->column('word');
25→    }
26→
27→    /**
28→     * Compute a did-you-mean suggestion via Levenshtein distance.
29→     */
30→    public function getDidYouMean(int $orgId, string $query): ?array
31→    {
32→        $query = trim(mb_strtolower($query));
33→        if ($query === '') {
34→            return null;
35→        }
36→
37→        $allWords = SearchDictionary::where('organization_id', $orgId)
38→            ->column('word');
39→
40→        if (empty($allWords)) {
41→            return null;
42→        }
43→
44→        $closestWord     = null;
45→        $closestDistance  = PHP_INT_MAX;
46→
47→        foreach ($allWords as $word) {
48→            $lowerWord = mb_strtolower($word);
49→            $distance  = levenshtein($query, $lowerWord);
50→
51→            if ($distance < $closestDistance) {
52→                $closestDistance = $distance;
53→                $closestWord    = $word;
54→            }
55→        }
56→
57→        // Only suggest if distance <= 2 and distance > 0 (not an exact match)
58→        if ($closestWord !== null && $closestDistance > 0 && $closestDistance <= 2) {
59→            $maxLen     = max(mb_strlen($query), mb_strlen($closestWord));
60→            $confidence = $maxLen > 0 ? 1 - ($closestDistance / $maxLen) : 0;
61→
62→            return [
63→                'original'   => $query,
64→                'suggestion' => $closestWord,
65→                'confidence' => round($confidence, 4),
66→            ];
67→        }
68→
69→        return null;
70→    }
71→}
