 1→<?php
 2→declare(strict_types=1);
 3→
 4→namespace app\middleware;
 5→
 6→use app\exception\AuthException;
 7→use app\model\ApiToken;
 8→use app\model\User;
 9→use think\Request;
10→use think\Response;
11→use think\facade\Session;
12→
13→/**
14→ * Authentication middleware.
15→ *
16→ * Supports two authentication strategies evaluated in order:
17→ *  1. Bearer token – SHA-256 hash lookup against the api_tokens table.
18→ *  2. Session – standard ThinkPHP session containing a user_id.
19→ *
20→ * On success the middleware sets:
21→ *  - $request->user      (app\model\User instance)
22→ *  - $request->orgId     (int – the user's organization_id)
23→ *  - $request->tokenAuth (bool – true when authenticated via Bearer token)
24→ */
25→class AuthMiddleware
26→{
27→    /**
28→     * @param Request  $request
29→     * @param \Closure $next
30→     * @return Response
31→     * @throws AuthException
32→     */
33→    public function handle(Request $request, \Closure $next): Response
34→    {
35→        $user      = null;
36→        $tokenAuth = false;
37→
38→        // ── Strategy 1: Bearer token ────────────────────────────────────
39→        $authHeader = $request->header('Authorization', '');
40→        if (stripos($authHeader, 'Bearer ') === 0) {
41→            $rawToken  = trim(substr($authHeader, 7));
42→            $tokenHash = hash('sha256', $rawToken);
43→
44→            /** @var ApiToken|null $apiToken */
45→            $apiToken = ApiToken::where('token_hash', $tokenHash)
46→                ->whereNull('revoked_at')
47→                ->where('expires_at', '>', date('Y-m-d H:i:s'))
48→                ->find();
49→
50→            if ($apiToken && $apiToken->isValid()) {
51→                $user      = $apiToken->user;
52→                $tokenAuth = true;
53→
54→                // Touch last_used_at without triggering model events.
55→                $apiToken->last_used_at = date('Y-m-d H:i:s');
56→                $apiToken->save();
57→            }
58→        }
59→
60→        // ── Strategy 2: Session ─────────────────────────────────────────
61→        if ($user === null) {
62→            $userId = Session::get('user_id');
63→            if ($userId) {
64→                $user = User::with(['roles'])->find($userId);
65→            }
66→        }
67→
68→        // ── No valid credentials ────────────────────────────────────────
69→        if ($user === null) {
70→            throw new AuthException('Authentication required', 40101);
71→        }
72→
73→        // ── Account status check ────────────────────────────────────────
74→        if ($user->status !== 'active') {
75→            throw new AuthException('Account disabled', 40102);
76→        }
77→
78→        // ── Populate request context ────────────────────────────────────
79→        $request->user      = $user;
80→        $request->orgId     = (int) $user->organization_id;
81→        $request->tokenAuth = $tokenAuth;
82→
83→        return $next($request);
84→    }
85→}
