 1→<?php
 2→declare(strict_types=1);
 3→
 4→namespace app\middleware;
 5→
 6→use think\Request;
 7→use think\Response;
 8→
 9→/**
10→ * CORS middleware for the decoupled frontend.
11→ *
12→ * Reads allowed origins from the CORS_ALLOWED_ORIGINS environment variable
13→ * (comma-separated list, default '*') and attaches the appropriate headers
14→ * to every response.  Preflight OPTIONS requests are short-circuited with a
15→ * 204 No Content response.
16→ */
17→class CorsMiddleware
18→{
19→    /**
20→     * @param Request  $request
21→     * @param \Closure $next
22→     * @return Response
23→     */
24→    public function handle(Request $request, \Closure $next): Response
25→    {
26→        $allowedOriginsRaw = env('CORS_ALLOWED_ORIGINS', '*');
27→        $allowedOrigins    = array_map('trim', explode(',', (string) $allowedOriginsRaw));
28→        $requestOrigin     = $request->header('Origin', '');
29→
30→        // Determine the value for the Access-Control-Allow-Origin header.
31→        if (in_array('*', $allowedOrigins, true)) {
32→            $origin = '*';
33→        } elseif (in_array($requestOrigin, $allowedOrigins, true)) {
34→            $origin = $requestOrigin;
35→        } else {
36→            $origin = '';
37→        }
38→
39→        // Handle preflight OPTIONS requests immediately.
40→        if ($request->isOptions()) {
41→            return Response::create('', 'html', 204)
42→                ->header([
43→                    'Access-Control-Allow-Origin'      => $origin,
44→                    'Access-Control-Allow-Methods'     => 'GET, POST, PUT, DELETE, OPTIONS',
45→                    'Access-Control-Allow-Headers'     => 'Content-Type, Authorization, X-Requested-With',
46→                    'Access-Control-Allow-Credentials' => 'true',
47→                    'Access-Control-Max-Age'           => '86400',
48→                ]);
49→        }
50→
51→        /** @var Response $response */
52→        $response = $next($request);
53→
54→        if ($origin !== '') {
55→            $response->header([
56→                'Access-Control-Allow-Origin'      => $origin,
57→                'Access-Control-Allow-Methods'     => 'GET, POST, PUT, DELETE, OPTIONS',
58→                'Access-Control-Allow-Headers'     => 'Content-Type, Authorization, X-Requested-With',
59→                'Access-Control-Allow-Credentials' => 'true',
60→                'Access-Control-Max-Age'           => '86400',
61→            ]);
62→        }
63→
64→        return $response;
65→    }
66→}
