 1→<?php
 2→declare(strict_types=1);
 3→
 4→namespace app\middleware;
 5→
 6→use app\exception\ForbiddenException;
 7→use app\exception\NotFoundException;
 8→use think\Request;
 9→use think\Response;
10→
11→/**
12→ * Organization isolation middleware.
13→ *
14→ * Ensures that resource access is scoped to the authenticated user's
15→ * organization.  While model-level scopeOrg() handles query filtering, this
16→ * middleware provides a defence-in-depth check for single-resource routes
17→ * (e.g. GET /api/listings/:id) by verifying that the target record belongs
18→ * to the same org as the requesting user.
19→ */
20→class OrgIsolationMiddleware
21→{
22→    /**
23→     * Map of route prefix segments to their corresponding model classes.
24→     */
25→    private const RESOURCE_MODEL_MAP = [
26→        'listings'   => \app\model\Listing::class,
27→        'orders'     => \app\model\Order::class,
28→        'reviews'    => \app\model\Review::class,
29→        'media'      => \app\model\Media::class,
30→        'users'      => \app\model\User::class,
31→    ];
32→
33→    /**
34→     * @param Request  $request
35→     * @param \Closure $next
36→     * @return Response
37→     * @throws ForbiddenException
38→     * @throws NotFoundException
39→     */
40→    public function handle(Request $request, \Closure $next): Response
41→    {
42→        // Ensure orgId is always set.
43→        if (empty($request->orgId) && $request->user) {
44→            $request->orgId = (int) $request->user->organization_id;
45→        }
46→
47→        // Attempt to verify the resource belongs to the user's org.
48→        $resourceId = $request->route('id');
49→
50→        if ($resourceId !== null && $request->orgId) {
51→            $modelClass = $this->resolveModel($request);
52→
53→            if ($modelClass !== null) {
54→                $record = $modelClass::find($resourceId);
55→
56→                if ($record === null) {
57→                    throw new NotFoundException('Resource not found', 40401);
58→                }
59→
60→                // Only check organization_id if the model actually has one.
61→                if (isset($record->organization_id)
62→                    && (int) $record->organization_id !== $request->orgId
63→                ) {
64→                    throw new ForbiddenException(
65→                        'You do not have access to this resource',
66→                        40302
67→                    );
68→                }
69→            }
70→        }
71→
72→        return $next($request);
73→    }
74→
75→    /**
76→     * Determine the model class based on the current request path.
77→     *
78→     * @param Request $request
79→     * @return string|null  Fully-qualified model class name, or null.
80→     */
81→    private function resolveModel(Request $request): ?string
82→    {
83→        $path = trim($request->pathinfo(), '/');
84→
85→        foreach (self::RESOURCE_MODEL_MAP as $prefix => $modelClass) {
86→            if (strpos($path, "api/{$prefix}") !== false) {
87→                return $modelClass;
88→            }
89→        }
90→
91→        return null;
92→    }
93→}
