 1→<?php
 2→declare(strict_types=1);
 3→
 4→namespace app\service;
 5→
 6→use app\exception\ForbiddenException;
 7→use app\exception\NotFoundException;
 8→use app\model\ApiToken;
 9→use think\Collection;
10→
11→class TokenService
12→{
13→    /**
14→     * Create a new API token for a user.
15→     */
16→    public function create(int $userId, string $name, int $expiresInDays = 90): array
17→    {
18→        $plaintext = generate_token();
19→        $tokenHash = hash('sha256', $plaintext);
20→
21→        $token = new ApiToken();
22→        $token->user_id    = $userId;
23→        $token->name       = $name;
24→        $token->token_hash = $tokenHash;
25→        $token->expires_at = date('Y-m-d\TH:i:s\Z', strtotime("+{$expiresInDays} days"));
26→        $token->save();
27→
28→        return [
29→            'token'           => $token,
30→            'plaintext_token' => $plaintext,
31→        ];
32→    }
33→
34→    /**
35→     * List all active (non-revoked) tokens for a user.
36→     */
37→    public function listForUser(int $userId): Collection
38→    {
39→        return ApiToken::where('user_id', $userId)
40→            ->whereNull('revoked_at')
41→            ->order('created_at', 'desc')
42→            ->select();
43→    }
44→
45→    /**
46→     * Revoke a token, verifying ownership.
47→     */
48→    public function revoke(int $tokenId, int $userId): void
49→    {
50→        $token = ApiToken::find($tokenId);
51→        if (!$token) {
52→            throw new NotFoundException('Token not found', 40401);
53→        }
54→        if ((int) $token->user_id !== $userId) {
55→            throw new ForbiddenException('You do not own this token');
56→        }
57→        $token->revoked_at = date('Y-m-d\TH:i:s\Z');
58→        $token->save();
59→    }
60→
61→    /**
62→     * Rotate a token: revoke old, create new with same name and remaining expiry.
63→     */
64→    public function rotate(int $tokenId, int $userId): array
65→    {
66→        $oldToken = ApiToken::find($tokenId);
67→        if (!$oldToken) {
68→            throw new NotFoundException('Token not found', 40401);
69→        }
70→        if ((int) $oldToken->user_id !== $userId) {
71→            throw new ForbiddenException('You do not own this token');
72→        }
73→
74→        // Calculate remaining days
75→        $expiresTimestamp = strtotime($oldToken->expires_at);
76→        $remainingSeconds = max($expiresTimestamp - time(), 86400); // at least 1 day
77→        $remainingDays = (int) ceil($remainingSeconds / 86400);
78→
79→        // Revoke old
80→        $oldToken->revoked_at = date('Y-m-d\TH:i:s\Z');
81→        $oldToken->save();
82→
83→        // Create new with same name and remaining expiry
84→        return $this->create($userId, $oldToken->name, $remainingDays);
85→    }
86→}
