105→        }
106→        if ((int) $review->user_id !== (int) $this->request->user->id) {
107→            throw new ForbiddenException('You do not own this review');
108→        }
109→
110→        $this->reviewService->destroy(
111→            (int) $id,
112→            (int) $this->request->user->id
113→        );
114→
115→        return json([
116→            'code'    => 0,
117→            'message' => 'Review deleted successfully',
118→            'data'    => null,
119→        ], 200);
120→    }
121→}
