 16→/**
 17→ * Fill missing values in listing metadata from behavior events.
 18→ *
 19→ * For each organization, counts behavior_events grouped by listing for view,
 20→ * favorite, and click events, then compares with the listing's denormalized
 21→ * counters (view_count, favorite_count, comment_count). Updates listings
 22→ * where counters have drifted.
 23→ */
 24→class GovernanceFillCommand extends Command
 25→{
 26→    protected function configure(): void
 27→    {
 28→        $this->setName('governance:fill')
 29→             ->setDescription('Fill missing values in listing metadata from behavior events');
 30→    }
 31→
 32→    protected function execute(Input $input, Output $output): int
 33→    {
 34→        $runId = $this->generateUuid();
 35→        $totalUpdated = 0;
 36→
 37→        $organizations = Organization::select();
 38→
 39→        foreach ($organizations as $org) {
 40→            $orgId = $org->id;
 41→
 42→            // Count behavior events by listing and type
 43→            $viewCounts = BehaviorEvent::where('organization_id', $orgId)
 44→                ->where('event_type', 'view')
 45→                ->where('target_type', 'listing')
 46→                ->group('target_id')
 47→                ->column('COUNT(*)', 'target_id');
 48→
 49→            $favoriteCounts = BehaviorEvent::where('organization_id', $orgId)
 50→                ->where('event_type', 'favorite')
 51→                ->where('target_type', 'listing')
 52→                ->group('target_id')
 53→                ->column('COUNT(*)', 'target_id');
 54→
 55→            $clickCounts = BehaviorEvent::where('organization_id', $orgId)
 56→                ->where('event_type', 'click')
 57→                ->where('target_type', 'listing')
 58→                ->group('target_id')
 59→                ->column('COUNT(*)', 'target_id');
 60→
 61→            // Get all listings for this org
 62→            $listings = Listing::where('organization_id', $orgId)->select();
 63→            $updatedCount = 0;
 64→
 65→            foreach ($listings as $listing) {
 66→                $lid = $listing->id;
 67→                $needsUpdate = false;
 68→
 69→                $actualViews = $viewCounts[$lid] ?? 0;
 70→                $actualFavorites = $favoriteCounts[$lid] ?? 0;
 71→                $actualClicks = $clickCounts[$lid] ?? 0;
 72→
 73→                if ((int) $listing->view_count !== $actualViews) {
 74→                    $listing->view_count = $actualViews;
 75→                    $needsUpdate = true;
 76→                }
 77→
 78→                if ((int) $listing->favorite_count !== $actualFavorites) {
 79→                    $listing->favorite_count = $actualFavorites;
 80→                    $needsUpdate = true;
 81→                }
 82→
 83→                if ((int) $listing->comment_count !== $actualClicks) {
 84→                    $listing->comment_count = $actualClicks;
 85→                    $needsUpdate = true;
 86→                }
 87→
 88→                if ($needsUpdate) {
 89→                    $listing->save();
 90→                    $updatedCount++;
 91→                }
 92→            }
 93→
 94→            $totalUpdated += $updatedCount;
 95→
 96→            // Record lineage
 97→            DataLineage::create([
 98→                'organization_id' => $orgId,
 99→                'job_name'        => 'governance:fill',
100→                'run_id'          => $runId,
101→                'step'            => 'fill_listing_counters',
102→                'input_count'     => count($listings),
103→                'output_count'    => $updatedCount,
104→                'removed_count'   => 0,
105→                'started_at'      => date('Y-m-d H:i:s'),
106→                'completed_at'    => date('Y-m-d H:i:s'),
107→                'created_at'      => date('Y-m-d H:i:s'),
108→            ]);
109→        }
110→
111→        Log::info("governance:fill completed: updated {$totalUpdated} listings (run_id={$runId})");
112→        $output->writeln("Fill complete: updated {$totalUpdated} listings.");
113→
114→        return 0;
115→    }
116→
117→    private function generateUuid(): string
118→    {
119→        $data = random_bytes(16);
120→        $data[6] = chr(ord($data[6]) & 0x0f | 0x40);
121→        $data[8] = chr(ord($data[8]) & 0x3f | 0x80);
122→
123→        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($data), 4));
124→    }
125→}
