12→/**
13→ * Record lineage summary for today's governance runs.
14→ *
15→ * Queries data_lineage for today's runs, computes totals across all steps,
16→ * and records a meta-lineage entry (step='daily_summary'). This is the
17→ * "lineage of lineage" ensuring a top-level record exists.
18→ */
19→class GovernanceLineageCommand extends Command
20→{
21→    protected function configure(): void
22→    {
23→        $this->setName('governance:lineage')
24→             ->setDescription("Record lineage summary for today's governance runs");
25→    }
26→
27→    protected function execute(Input $input, Output $output): int
28→    {
29→        $today = date('Y-m-d');
30→        $startOfDay = $today . ' 00:00:00';
31→        $endOfDay = $today . ' 23:59:59';
32→
33→        // Query all lineage records for today, excluding daily_summary to avoid self-referencing
34→        $todayRecords = DataLineage::where('created_at', '>=', $startOfDay)
35→            ->where('created_at', '<=', $endOfDay)
36→            ->where('step', '<>', 'daily_summary')
37→            ->select();
38→
39→        $totalInput = 0;
40→        $totalOutput = 0;
41→        $totalRemoved = 0;
42→
43→        foreach ($todayRecords as $record) {
44→            $totalInput += (int) $record->input_count;
45→            $totalOutput += (int) $record->output_count;
46→            $totalRemoved += (int) $record->removed_count;
47→        }
48→
49→        $runId = $this->generateUuid();
50→
51→        // Record the meta-lineage entry
52→        DataLineage::create([
53→            'organization_id' => null,
54→            'job_name'        => 'governance:lineage',
55→            'run_id'          => $runId,
56→            'step'            => 'daily_summary',
57→            'input_count'     => $totalInput,
58→            'output_count'    => $totalOutput,
59→            'removed_count'   => $totalRemoved,
60→            'metadata'        => json_encode([
61→                'date'         => $today,
62→                'record_count' => count($todayRecords),
63→                'steps'        => array_unique(array_column($todayRecords->toArray(), 'step')),
64→            ]),
65→            'started_at'      => date('Y-m-d H:i:s'),
66→            'completed_at'    => date('Y-m-d H:i:s'),
67→            'created_at'      => date('Y-m-d H:i:s'),
68→        ]);
69→
70→        Log::info("governance:lineage daily summary recorded for {$today}: input={$totalInput}, output={$totalOutput}, removed={$totalRemoved}");
71→        $output->writeln("Lineage summary recorded for {$today}.");
72→
73→        return 0;
74→    }
75→
76→    private function generateUuid(): string
77→    {
78→        $data = random_bytes(16);
79→        $data[6] = chr(ord($data[6]) & 0x0f | 0x40);
80→        $data[8] = chr(ord($data[8]) & 0x3f | 0x80);
81→
82→        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($data), 4));
83→    }
84→}
