  1→<?php
  2→declare(strict_types=1);
  3→
  4→namespace app\command;
  5→
  6→use app\model\BehaviorEvent;
  7→use app\model\DataLineage;
  8→use app\model\DataQualityMetric;
  9→use app\model\Listing;
 10→use app\model\ModerationQueue;
 11→use app\model\Organization;
 12→use app\model\Review;
 13→use think\console\Command;
 14→use think\console\Input;
 15→use think\console\Output;
 16→use think\facade\Db;
 17→use think\facade\Log;
 18→
 19→/**
 20→ * Compute data quality metrics for all organizations.
 21→ *
 22→ * Calculates and stores seven quality metrics per organization:
 23→ *   1. listing_completeness
 24→ *   2. event_dedup_ratio
 25→ *   3. missing_value_rate
 26→ *   4. counter_drift
 27→ *   5. review_credibility_distribution
 28→ *   6. moderation_queue_depth
 29→ *   7. stale_listing_rate
 30→ */
 31→class GovernanceQualityCommand extends Command
 32→{
 33→    protected function configure(): void
 34→    {
 35→        $this->setName('governance:quality')
 36→             ->setDescription('Compute data quality metrics for all organizations');
 37→    }
 38→
 39→    protected function execute(Input $input, Output $output): int
 40→    {
 41→        $organizations = Organization::select();
 42→        $orgCount = 0;
 43→        $today = date('Y-m-d');
 44→
 45→        foreach ($organizations as $org) {
 46→            $orgId = $org->id;
 47→            $metrics = [];
 48→
 49→            // 1. listing_completeness: % of listings where description, baggage_notes, and tags are all non-null
 50→            $totalListings = Listing::where('organization_id', $orgId)->count();
 51→            $completeListings = Listing::where('organization_id', $orgId)
 52→                ->whereNotNull('description')
 53→                ->whereNotNull('baggage_notes')
 54→                ->whereNotNull('tags')
 55→                ->count();
 56→            $metrics['listing_completeness'] = $totalListings > 0
 57→                ? round($completeListings / $totalListings, 4)
 58→                : 1.0;
 59→
 60→            // 2. event_dedup_ratio: events removed today / total events before dedup (from lineage)
 61→            $dedupLineage = DataLineage::where('organization_id', $orgId)
 62→                ->where('job_name', 'governance:dedup')
 63→                ->where('created_at', '>=', $today . ' 00:00:00')
 64→                ->where('created_at', '<=', $today . ' 23:59:59')
 65→                ->order('created_at', 'desc')
 66→                ->find();
 67→
 68→            if ($dedupLineage && $dedupLineage->input_count > 0) {
 69→                $metrics['event_dedup_ratio'] = round(
 70→                    (int) $dedupLineage->removed_count / (int) $dedupLineage->input_count,
 71→                    4
 72→                );
 73→            } else {
 74→                $metrics['event_dedup_ratio'] = 0.0;
 75→            }
 76→
 77→            // 3. missing_value_rate: % of listings with NULL description or NULL tags
 78→            $missingListings = Listing::where('organization_id', $orgId)
 79→                ->where(function ($query) {
 80→                    $query->whereNull('description')->whereOr('tags', null);
 81→                })
 82→                ->count();
 83→            $metrics['missing_value_rate'] = $totalListings > 0
 84→                ? round($missingListings / $totalListings, 4)
 85→                : 0.0;
 86→
 87→            // 4. counter_drift: MAX(ABS(listing.view_count - actual_event_count))
 88→            $maxDrift = 0;
 89→            $listings = Listing::where('organization_id', $orgId)->select();
 90→            foreach ($listings as $listing) {
 91→                $actualViews = BehaviorEvent::where('organization_id', $orgId)
 92→                    ->where('event_type', 'view')
 93→                    ->where('target_type', 'listing')
 94→                    ->where('target_id', $listing->id)
 95→                    ->count();
 96→                $drift = abs((int) $listing->view_count - $actualViews);
 97→                if ($drift > $maxDrift) {
 98→                    $maxDrift = $drift;
 99→                }
100→            }
101→            $metrics['counter_drift'] = $maxDrift;
102→
103→            // 5. review_credibility_distribution: JSON with min, p25, median, p75, max
104→            $scores = Review::where('organization_id', $orgId)
105→                ->whereNotNull('credibility_score')
106→                ->order('credibility_score', 'asc')
107→                ->column('credibility_score');
108→
109→            if (!empty($scores)) {
110→                $count = count($scores);
111→                $metrics['review_credibility_distribution'] = json_encode([
112→                    'min'    => round((float) $scores[0], 4),
113→                    'p25'    => round((float) $scores[(int) floor($count * 0.25)], 4),
114→                    'median' => round((float) $scores[(int) floor($count * 0.5)], 4),
115→                    'p75'    => round((float) $scores[(int) floor($count * 0.75)], 4),
116→                    'max'    => round((float) $scores[$count - 1], 4),
117→                ]);
118→            } else {
119→                $metrics['review_credibility_distribution'] = json_encode([
120→                    'min' => 0, 'p25' => 0, 'median' => 0, 'p75' => 0, 'max' => 0,
121→                ]);
122→            }
123→
124→            // 6. moderation_queue_depth: COUNT of pending items
125→            $metrics['moderation_queue_depth'] = ModerationQueue::where('organization_id', $orgId)
126→                ->where('status', 'pending')
127→                ->count();
128→
129→            // 7. stale_listing_rate: % of active listings where last_activity_at < 7 days ago (or NULL)
130→            $activeListings = Listing::where('organization_id', $orgId)
131→                ->where('status', 'active')
132→                ->count();
133→            $sevenDaysAgo = date('Y-m-d H:i:s', strtotime('-7 days'));
134→            $staleListings = Listing::where('organization_id', $orgId)
135→                ->where('status', 'active')
136→                ->where(function ($query) use ($sevenDaysAgo) {
137→                    $query->whereNull('last_activity_at')
138→                          ->whereOr('last_activity_at', '<', $sevenDaysAgo);
139→                })
140→                ->count();
141→            $metrics['stale_listing_rate'] = $activeListings > 0
142→                ? round($staleListings / $activeListings, 4)
143→                : 0.0;
144→
145→            // Store each metric
146→            foreach ($metrics as $metricName => $value) {
147→                DataQualityMetric::create([
148→                    'organization_id' => $orgId,
149→                    'metric_name'     => $metricName,
150→                    'metric_value'    => is_string($value) ? $value : (string) $value,
151→                    'computed_at'     => date('Y-m-d H:i:s'),
152→                    'created_at'      => date('Y-m-d H:i:s'),
153→                ]);
154→            }
155→
156→            $orgCount++;
157→        }
158→
159→        Log::info("governance:quality completed: metrics computed for {$orgCount} organizations");
160→        $output->writeln("Quality metrics computed for {$orgCount} organizations.");
161→
162→        return 0;
163→    }
164→}
