 17→        { value: 'resolved', label: 'Resolved' }
 18→    ];
 19→
 20→    var ROLES = [
 21→        { value: '', label: 'All' },
 22→        { value: 'passenger', label: 'As Passenger' },
 23→        { value: 'driver', label: 'As Driver' }
 24→    ];
