111→        return '<div class="layui-card rc-order-card" style="margin-bottom:12px;cursor:pointer;" data-order-id="' + order.id + '">' +
112→            '<div class="layui-card-body" style="padding:16px;">' +
113→            '<div style="display:flex;justify-content:space-between;align-items:flex-start;">' +
114→            '<div style="flex:1;">' +
115→            '<h3 style="margin:0 0 6px 0;font-size:16px;">' + title + '</h3>' +
116→            '<div style="margin-bottom:6px;">' +
117→            '<span style="color:#666;">with <strong>' + RCUtil.escapeHtml(party) + '</strong></span>' +
118→            '<span style="margin-left:12px;">' + RCUtil.statusBadge(order.status) + '</span>' +
119→            '</div>' +
120→            '<div>' + timestamps + '</div>' +
121→            '</div>' +
122→            '<div style="flex-shrink:0;margin-left:16px;">' +
123→            '<button type="button" class="layui-btn layui-btn-sm ' + action.cls +
124→            ' rc-order-view-btn" data-order-id="' + order.id + '">' + action.label + '</button>' +
125→            '</div></div></div></div>';
126→    }
127→
128→    function renderContent(container) {
129→        var html = '<div class="rc-orders-page" style="max-width:900px;margin:0 auto;padding:20px;">' +
130→            '<h2 style="margin-bottom:20px;">My Orders</h2>';
131→
132→        // Filter bar
133→        html += '<div style="display:flex;align-items:center;gap:16px;margin-bottom:20px;flex-wrap:wrap;">' +
134→            buildRoleTabs() +
135→            '<select id="rc-order-status-filter" lay-ignore style="height:32px;border:1px solid #e6e6e6;border-radius:2px;padding:0 8px;">' +
136→            buildStatusOption() +
137→            '</select></div>';
138→
139→        // Order list
140→        html += '<div id="rc-orders-list">';
141→        if (state.loading) {
142→            html += renderSkeleton();
143→        } else if (state.error) {
144→            html += '<div class="layui-card"><div class="layui-card-body" style="padding:20px;color:#FF5722;">' +
145→                '<i class="layui-icon layui-icon-close-fill"></i> ' +
146→                RCUtil.escapeHtml(state.error) + '</div></div>';
147→        } else if (state.orders.length === 0) {
148→            html += RCUtil.emptyState('No orders yet. Browse listings to find a ride or post your own trip request.');
149→        } else {
150→            state.orders.forEach(function (order) {
151→                html += renderOrderCard(order);
152→            });
153→        }
154→        html += '</div>';
155→
156→        // Pagination
157→        html += '<div id="rc-orders-pagination" style="margin-top:16px;text-align:center;"></div>';
158→        html += '</div>';
159→
160→        container.innerHTML = html;
161→    }
162→
163→    function bindEvents(container) {
164→        // Role tabs
165→        var tabs = container.querySelectorAll('.rc-role-tabs button');
166→        tabs.forEach(function (btn) {
167→            btn.addEventListener('click', function () {
168→                state.role = this.getAttribute('data-role');
169→                state.page = 1;
170→                loadOrders(container);
171→            });
172→        });
173→
174→        // Status filter
175→        var statusSelect = container.querySelector('#rc-order-status-filter');
176→        if (statusSelect) {
177→            statusSelect.addEventListener('change', function () {
178→                state.status = this.value;
179→                state.page = 1;
180→                loadOrders(container);
181→            });
182→        }
183→
184→        // Card click / View button
185→        container.querySelectorAll('.rc-order-card').forEach(function (card) {
186→            card.addEventListener('click', function (e) {
187→                var id = this.getAttribute('data-order-id');
188→                if (id) RCRouter.navigate('#/orders/' + id);
189→            });
190→        });
191→
192→        // Pagination
193→        if (state.lastPage > 1) {
194→            RCUtil.renderPagination('rc-orders-pagination', {
195→                total: state.total,
196→                page: state.page,
197→                perPage: state.perPage,
198→                onChange: function (page) {
199→                    state.page = page;
200→                    loadOrders(container);
201→                }
202→            });
203→        }
204→    }
205→
206→    function loadOrders(container) {
207→        state.loading = true;
208→        state.error = null;
209→        renderContent(container);
210→
211→        var params = {
212→            page: state.page,
213→            per_page: state.perPage
214→        };
215→        if (state.role) params.role = state.role;
216→        if (state.status) params.status = state.status;
217→
218→        RCApi.getOrders(params).then(function (res) {
219→            state.loading = false;
220→            state.orders = res.data || [];
221→            var meta = res.meta || {};
222→            state.total = meta.total || 0;
223→            state.page = meta.page || 1;
224→            state.lastPage = meta.last_page || 1;
225→            renderContent(container);
226→            bindEvents(container);
227→        }).catch(function (err) {
228→            state.loading = false;
229→            state.error = (err && err.message) ? err.message : 'Failed to load orders';
230→            renderContent(container);
231→            bindEvents(container);
232→        });
233→    }
234→
235→    return {
236→        render: function (container, params) {
237→            state.role = (params && params.role) || '';
238→            state.status = (params && params.status) || '';
239→            state.page = 1;
240→            state.orders = [];
241→            state.error = null;
242→            loadOrders(container);
243→        }
244→    };
245→})();
246→
247→if (typeof module !== 'undefined' && module.exports) {
248→    module.exports = OrdersPage;
249→}
