238→            });
239→            star.addEventListener('mouseenter', function () {
240→                var val = parseInt(this.getAttribute('data-value'), 10);
241→                container.querySelectorAll('.rc-star').forEach(function (s) {
242→                    var sv = parseInt(s.getAttribute('data-value'), 10);
243→                    s.style.color = sv <= val ? '#FFB800' : '#d2d2d2';
244→                    s.textContent = sv <= val ? '\u2605' : '\u2606';
245→                });
246→            });
247→            star.addEventListener('mouseleave', function () {
248→                container.querySelectorAll('.rc-star').forEach(function (s) {
249→                    var sv = parseInt(s.getAttribute('data-value'), 10);
250→                    s.style.color = sv <= state.rating ? '#FFB800' : '#d2d2d2';
251→                    s.textContent = sv <= state.rating ? '\u2605' : '\u2606';
252→                });
253→            });
254→        });
255→
256→        // Text area
257→        var textArea = container.querySelector('#rc-review-text');
258→        if (textArea) {
259→            textArea.addEventListener('input', function () {
260→                state.text = this.value;
261→                var counter = container.querySelector('#rc-review-char-count');
262→                if (counter) {
263→                    counter.textContent = state.text.length;
264→                    var nearLimit = state.text.length > MAX_TEXT * 0.9;
265→                    var overLimit = state.text.length > MAX_TEXT;
266→                    counter.parentElement.style.color = overLimit ? '#FF5722' : (nearLimit ? '#FF9800' : '#999');
267→                }
268→                // Update submit button
269→                var submitBtn = container.querySelector('#rc-review-submit');
270→                if (submitBtn) {
271→                    var ok = canSubmit();
272→                    submitBtn.disabled = !ok;
273→                    if (ok) submitBtn.classList.remove('layui-btn-disabled');
274→                    else submitBtn.classList.add('layui-btn-disabled');
275→                }
276→            });
277→        }
278→
279→        // File input
280→        var dropZone = container.querySelector('#rc-drop-zone');
281→        var fileInput = container.querySelector('#rc-file-input');
282→        if (dropZone && fileInput) {
283→            dropZone.addEventListener('click', function () {
284→                fileInput.click();
285→            });
286→            fileInput.addEventListener('change', function () {
287→                if (this.files && this.files.length) {
288→                    addFiles(this.files);
289→                    setTimeout(function () {
290→                        renderPage(container);
291→                        bindEvents(container);
292→                    }, 300);
293→                }
294→            });
295→            dropZone.addEventListener('dragover', function (e) {
296→                e.preventDefault();
297→                this.style.borderColor = '#1E9FFF';
298→            });
299→            dropZone.addEventListener('dragleave', function () {
300→                this.style.borderColor = '#d2d2d2';
301→            });
302→            dropZone.addEventListener('drop', function (e) {
303→                e.preventDefault();
304→                this.style.borderColor = '#d2d2d2';
305→                if (e.dataTransfer && e.dataTransfer.files.length) {
306→                    addFiles(e.dataTransfer.files);
307→                    setTimeout(function () {
308→                        renderPage(container);
309→                        bindEvents(container);
310→                    }, 300);
311→                }
312→            });
313→        }
314→
315→        // Remove file
316→        container.querySelectorAll('.rc-remove-file').forEach(function (btn) {
317→            btn.addEventListener('click', function () {
318→                var idx = parseInt(this.getAttribute('data-idx'), 10);
319→                state.files.splice(idx, 1);
320→                renderPage(container);
321→                bindEvents(container);
322→            });
323→        });
324→
325→        // Submit
326→        var submitBtn = container.querySelector('#rc-review-submit');
327→        if (submitBtn) {
328→            submitBtn.addEventListener('click', function () {
329→                handleSubmit(container);
330→            });
331→        }
332→    }
333→
334→    function handleSubmit(container) {
335→        if (!canSubmit() || state.submitting) return;
336→
337→        state.submitting = true;
338→        state.submitError = null;
339→        renderPage(container);
340→        bindEvents(container);
341→
342→        var formData = new FormData();
343→        formData.append('order_id', state.orderId);
344→        formData.append('rating', state.rating);
345→        formData.append('text', state.text.trim());
346→        state.files.forEach(function (f) {
347→            formData.append('files[]', f);
348→        });
349→
350→        RCApi.createReview(formData).then(function (res) {
351→            state.submitting = false;
352→            layui.layer.msg(res.message || 'Review submitted!', { icon: 1 });
353→
354→            // Check for duplicate detection
355→            if (res.data && res.data.status === 'pending') {
356→                layui.layer.msg('This review appears to be similar to one you recently submitted. It has been sent for review.', {
357→                    icon: 0, time: 4000
358→                });
359→            }
360→
361→            RCRouter.navigate('#/orders/' + state.orderId);
362→        }).catch(function (err) {
363→            state.submitting = false;
364→            var msg = (err && err.message) ? err.message : 'Failed to submit review';
365→
366→            // Rate limit error detection
367→            if (err && err.status === 429) {
368→                var retryAfter = err.retry_after || '';
369→                msg = "You've submitted 3 reviews in the last hour. Please wait " +
370→                    (retryAfter ? retryAfter : 'a while') + ' before submitting another.';
371→            }
372→
373→            state.submitError = msg;
374→            renderPage(container);
375→            bindEvents(container);
376→        });
377→    }
378→
379→    function loadOrder(container) {
380→        state.loading = true;
381→        renderPage(container);
382→
383→        RCApi.getOrder(state.orderId).then(function (res) {
384→            state.loading = false;
385→            state.order = res.data;
386→            renderPage(container);
387→            bindEvents(container);
388→        }).catch(function (err) {
389→            state.loading = false;
390→            state.error = (err && err.message) ? err.message : 'Failed to load order';
391→            renderPage(container);
392→        });
393→    }
394→
395→    return {
396→        render: function (container, params) {
397→            state.orderId = params && params.id ? params.id : null;
398→            state.order = null;
399→            state.rating = 0;
400→            state.text = '';
401→            state.files = [];
402→            state.error = null;
403→            state.submitError = null;
404→            state.submitting = false;
405→
406→            if (!state.orderId) {
407→                state.error = 'No order ID provided';
408→                renderPage(container);
409→                return;
410→            }
411→            loadOrder(container);
412→        }
413→    };
414→})();
415→
416→if (typeof module !== 'undefined' && module.exports) {
417→    module.exports = ReviewFormPage;
418→}
