267→    function readFilterState(container) {
268→        var userEl = container.querySelector('#rc-audit-user');
269→        var actionEl = container.querySelector('#rc-audit-action');
270→        var resourceEl = container.querySelector('#rc-audit-resource');
271→        var fromEl = container.querySelector('#rc-audit-from');
272→        var toEl = container.querySelector('#rc-audit-to');
273→
274→        state.userId = userEl ? userEl.value.trim() : '';
275→        state.action = actionEl ? actionEl.value : '';
276→        state.resourceType = resourceEl ? resourceEl.value : '';
277→        state.fromDate = fromEl ? fromEl.value : state.fromDate;
278→        state.toDate = toEl ? toEl.value : state.toDate;
279→    }
280→
281→    function loadLogs(container) {
282→        state.loading = true;
283→        state.error = null;
284→        renderContent(container);
285→        bindEvents(container);
286→
287→        var params = { page: state.page, per_page: state.perPage };
288→        if (state.userId) params.user_id = state.userId;
289→        if (state.action) params.action = state.action;
290→        if (state.resourceType) params.resource_type = state.resourceType;
291→        if (state.fromDate) params.from_date = state.fromDate;
292→        if (state.toDate) params.to_date = state.toDate;
293→        if (state.unmask) params.unmask = true;
294→
295→        RCApi.getAuditLogs(params).then(function (res) {
296→            state.loading = false;
297→            state.logs = res.data || [];
298→            var meta = res.meta || {};
299→            state.total = meta.total || 0;
300→            state.page = meta.page || 1;
301→            state.lastPage = meta.last_page || 1;
302→            renderContent(container);
303→            bindEvents(container);
304→        }).catch(function (err) {
305→            state.loading = false;
306→            state.error = (err && err.message) ? err.message : 'Failed to load audit logs';
307→            renderContent(container);
308→            bindEvents(container);
309→        });
310→    }
311→
312→    return {
313→        render: function (container, params) {
314→            state.userId = '';
315→            state.action = '';
316→            state.resourceType = '';
317→            state.fromDate = (params && params.from_date) || defaultFromDate();
318→            state.toDate = (params && params.to_date) || defaultToDate();
319→            state.unmask = false;
320→            state.page = 1;
321→            state.logs = [];
322→            state.expandedRows = {};
323→            state.error = null;
324→
325→            if (!RCAuth.isAdmin()) {
326→                renderContent(container);
327→                return;
328→            }
329→            loadLogs(container);
330→        }
331→    };
332→})();
333→
334→if (typeof module !== 'undefined' && module.exports) {
335→    module.exports = AdminAuditPage;
336→}
