141→                this.style.backgroundColor = '#009688';
142→                this.style.color = '#fff';
143→                currentSort = this.getAttribute('data-sort');
144→                currentPage = 1;
145→                loadListings();
146→            });
147→        }
148→
149→        // Set initial active tab style
150→        var activeTab = container.querySelector('.rc-sort-active');
151→        if (activeTab) {
152→            activeTab.style.backgroundColor = '#009688';
153→            activeTab.style.color = '#fff';
154→        }
155→
156→        // Apply filters
157→        document.getElementById('apply-filters').addEventListener('click', function() {
158→            gatherFilters();
159→            currentPage = 1;
160→            loadListings();
161→        });
162→
163→        // Clear filters
164→        document.getElementById('clear-filters').addEventListener('click', function() {
165→            var checkboxes = container.querySelectorAll('input[name="vtype"]');
166→            for (var c = 0; c < checkboxes.length; c++) {
167→                checkboxes[c].checked = false;
168→            }
169→            document.getElementById('rider-min').value = '1';
170→            document.getElementById('rider-max').value = '6';
171→            document.getElementById('filter-status').value = '';
172→            layui.form.render();
173→            currentFilters = {};
174→            currentPage = 1;
175→            loadListings();
176→        });
177→
178→        function gatherFilters() {
179→            currentFilters = {};
180→            var checkedTypes = [];
181→            var checkboxes = container.querySelectorAll('input[name="vtype"]:checked');
182→            for (var c = 0; c < checkboxes.length; c++) {
183→                checkedTypes.push(checkboxes[c].value);
184→            }
185→            if (checkedTypes.length) {
186→                currentFilters.vehicle_type = checkedTypes.join(',');
187→            }
188→            var riderMin = parseInt(document.getElementById('rider-min').value, 10);
189→            var riderMax = parseInt(document.getElementById('rider-max').value, 10);
190→            if (riderMin && riderMin > 1) currentFilters.rider_count_min = riderMin;
191→            if (riderMax && riderMax < 6) currentFilters.rider_count_max = riderMax;
192→            var statusVal = document.getElementById('filter-status').value;
193→            if (statusVal) currentFilters.status = statusVal;
194→        }
195→
196→        function renderSearchHistory() {
197→            var historyDiv = document.getElementById('search-history');
198→            var history = RCUtil.getSearchHistory();
199→            if (!history || !history.length) {
200→                historyDiv.innerHTML = '';
201→                return;
202→            }
203→            var chips = history.slice(0, 8).map(function(term) {
204→                return '<span class="rc-history-chip" style="display:inline-block;padding:3px 10px;margin:3px;background:#f0f0f0;border-radius:12px;font-size:12px;cursor:pointer;color:#666;">' +
205→                    RCUtil.escapeHtml(term) + '</span>';
206→            }).join('');
207→            historyDiv.innerHTML = '<span style="font-size:12px;color:#999;margin-right:6px;">Recent:</span>' + chips;
208→            var chipEls = historyDiv.querySelectorAll('.rc-history-chip');
209→            for (var h = 0; h < chipEls.length; h++) {
210→                chipEls[h].addEventListener('click', function() {
211→                    searchInput.value = this.textContent;
212→                    doSearch();
213→                });
214→            }
215→        }
216→
217→        function doSearch() {
218→            currentQuery = searchInput.value.trim();
219→            if (currentQuery) {
220→                RCUtil.addSearchHistory(currentQuery);
221→                renderSearchHistory();
222→            }
223→            currentPage = 1;
224→            loadListings();
225→        }
226→
227→        function loadListings() {
228→            var resultsDiv = document.getElementById('listings-results');
229→            resultsDiv.innerHTML = RCUtil.skeleton(4);
230→
231→            var apiParams = { page: currentPage, per_page: 12, sort: currentSort };
232→            if (currentQuery) apiParams.q = currentQuery;
233→            if (currentFilters.vehicle_type) apiParams.vehicle_type = currentFilters.vehicle_type;
234→            if (currentFilters.rider_count_min) apiParams.rider_count_min = currentFilters.rider_count_min;
235→            if (currentFilters.rider_count_max) apiParams.rider_count_max = currentFilters.rider_count_max;
236→            if (currentFilters.status) apiParams.status = currentFilters.status;
237→
238→            RCApi.getListings(apiParams).then(function(data) {
239→                var dymDiv = document.getElementById('did-you-mean');
240→
241→                if (!data.listings || data.listings.length === 0) {
242→                    // Did you mean
243→                    if (currentQuery && data.did_you_mean) {
244→                        dymDiv.innerHTML = 'Did you mean: <a href="javascript:;" class="rc-dym-link" style="color:#009688;text-decoration:underline;">' +
245→                            RCUtil.escapeHtml(data.did_you_mean) + '</a>?';
246→                        dymDiv.style.display = 'block';
247→                        dymDiv.querySelector('.rc-dym-link').addEventListener('click', function() {
248→                            searchInput.value = data.did_you_mean;
249→                            doSearch();
250→                        });
251→                    } else {
252→                        dymDiv.style.display = 'none';
253→                    }
254→
255→                    // No results fallback
256→                    if (currentQuery && data.recent_active && data.recent_active.length) {
257→                        resultsDiv.innerHTML =
258→                            '<div class="rc-empty-state" style="text-align:center;padding:30px 0;color:#999;">' +
259→                            '<i class="layui-icon layui-icon-search" style="font-size:48px;display:block;margin-bottom:12px;"></i>' +
260→                            '<p>No rides found for "<strong>' + RCUtil.escapeHtml(currentQuery) +
261→                            '</strong>". Here are some recently active listings:</p></div>' +
262→                            renderListingCards(data.recent_active, false);
263→                    } else {
264→                        resultsDiv.innerHTML = RCUtil.emptyState(
265→                            'No trip requests yet. Be the first to post one!',
266→                            'Post a Trip Request', '#/listings/create'
267→                        );
268→                    }
269→                    document.getElementById('listings-pagination').innerHTML = '';
270→                    return;
271→                }
272→
273→                dymDiv.style.display = 'none';
274→
275→                // Check for did_you_mean even with results
276→                if (currentQuery && data.did_you_mean) {
277→                    dymDiv.innerHTML = 'Did you mean: <a href="javascript:;" class="rc-dym-link" style="color:#009688;text-decoration:underline;">' +
278→                        RCUtil.escapeHtml(data.did_you_mean) + '</a>?';
279→                    dymDiv.style.display = 'block';
280→                    dymDiv.querySelector('.rc-dym-link').addEventListener('click', function() {
281→                        searchInput.value = data.did_you_mean;
282→                        doSearch();
283→                    });
284→                }
285→
286→                resultsDiv.innerHTML =
287→                    '<div class="rc-results-count" style="margin-bottom:12px;color:#666;font-size:13px;">' +
288→                    '<strong>' + data.meta.total + '</strong> result' + (data.meta.total !== 1 ? 's' : '') +
289→                    (currentQuery ? ' for "<em>' + RCUtil.escapeHtml(currentQuery) + '</em>"' : '') +
290→                    '</div>' +
291→                    renderListingCards(data.listings, !!currentQuery);
292→
293→                RCUtil.renderPagination('listings-pagination', data.meta.total, data.meta.page, data.meta.per_page, function(page) {
294→                    currentPage = page;
295→                    loadListings();
296→                    window.scrollTo(0, 0);
297→                });
298→            }).catch(function(err) {
299→                resultsDiv.innerHTML =
300→                    '<div class="rc-empty-state rc-error-state" style="text-align:center;padding:40px 0;color:#FF5722;">' +
301→                    '<i class="layui-icon layui-icon-face-cry" style="font-size:48px;display:block;margin-bottom:12px;"></i>' +
302→                    '<p>Failed to load listings: ' + RCUtil.escapeHtml(err.message || 'Unknown error') + '</p>' +
303→                    '<button class="layui-btn layui-btn-sm" id="retry-btn">Retry</button></div>';
304→                document.getElementById('listings-pagination').innerHTML = '';
305→                document.getElementById('retry-btn').addEventListener('click', function() {
306→                    loadListings();
307→                });
308→            });
309→        }
310→
311→        function renderListingCards(listings, showHighlights) {
312→            return '<div class="rc-listing-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:15px;">' +
313→                listings.map(function(l) {
314→                    var title = showHighlights && l.highlight && l.highlight.title
315→                        ? l.highlight.title
316→                        : RCUtil.escapeHtml(l.title);
317→                    var desc = showHighlights && l.highlight && l.highlight.description
318→                        ? l.highlight.description
319→                        : RCUtil.escapeHtml(RCUtil.truncate(l.description || '', 120));
320→                    var tags = (l.tags || []).map(function(t) {
321→                        return '<span class="rc-tag-chip" style="display:inline-block;padding:2px 8px;margin:2px;background:#e8f5e9;color:#388e3c;border-radius:10px;font-size:11px;">' +
322→                            RCUtil.escapeHtml(t) + '</span>';
323→                    }).join('');
324→                    var vehicleLabel = (l.vehicle_type || '').charAt(0).toUpperCase() + (l.vehicle_type || '').slice(1);
325→
326→                    return '<div class="rc-listing-card layui-card" style="cursor:pointer;" data-id="' + l.id + '">' +
327→                        '<div class="layui-card-header" style="display:flex;justify-content:space-between;align-items:center;">' +
328→                        '  <a href="#/listings/' + l.id + '" class="rc-listing-title" style="color:#333;font-weight:bold;text-decoration:none;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + title + '</a>' +
329→                        '  ' + RCUtil.statusBadge(l.status) +
330→                        '</div>' +
331→                        '<div class="layui-card-body" style="font-size:13px;">' +
332→                        '  <div class="rc-listing-meta" style="margin-bottom:8px;">' +
333→                        '    <div style="margin-bottom:4px;"><i class="layui-icon layui-icon-location" style="color:#009688;margin-right:4px;"></i><strong>Pickup:</strong> ' + RCUtil.escapeHtml(RCUtil.truncate(l.pickup_address || '', 40)) + '</div>' +
334→                        '    <div><i class="layui-icon layui-icon-location" style="color:#FF5722;margin-right:4px;"></i><strong>Drop-off:</strong> ' + RCUtil.escapeHtml(RCUtil.truncate(l.dropoff_address || '', 40)) + '</div>' +
335→                        '  </div>' +
336→                        '  <div class="rc-listing-details" style="margin-bottom:8px;display:flex;gap:12px;flex-wrap:wrap;color:#666;">' +
337→                        '    <span class="rc-detail-item"><i class="layui-icon layui-icon-group"></i> ' + l.rider_count + ' rider(s)</span>' +
338→                        '    <span class="rc-detail-item"><i class="layui-icon layui-icon-car"></i> ' + RCUtil.escapeHtml(vehicleLabel) + '</span>' +
339→                        '    <span class="rc-detail-item"><i class="layui-icon layui-icon-time"></i> ' + RCUtil.formatTime12h(l.time_window_start) + ' - ' + RCUtil.formatTime12h(l.time_window_end) + '</span>' +
340→                        '  </div>' +
341→                        '  <div class="rc-listing-desc" style="color:#555;margin-bottom:8px;line-height:1.5;">' + desc + '</div>' +
342→                        '  <div class="rc-listing-tags" style="margin-bottom:8px;">' + tags + '</div>' +
343→                        '  <div class="rc-listing-footer" style="display:flex;justify-content:space-between;align-items:center;color:#999;font-size:12px;border-top:1px solid #f0f0f0;padding-top:8px;">' +
344→                        '    <span>by ' + RCUtil.escapeHtml(l.user ? l.user.name : 'Unknown') + ' &middot; ' + RCUtil.formatDate(l.created_at) + '</span>' +
345→                        '    <span>' + (l.view_count || 0) + ' views &middot; ' + (l.favorite_count || 0) + ' favs</span>' +
346→                        '  </div>' +
347→                        '</div></div>';
348→                }).join('') + '</div>';
349→        }
350→
351→        // Apply initial URL params if present
352→        if (params && params.q) {
353→            searchInput.value = params.q;
354→            currentQuery = params.q;
355→        }
356→        if (params && params.status) {
357→            currentFilters.status = params.status;
358→            document.getElementById('filter-status').value = params.status;
359→            layui.form.render('select');
360→        }
361→
362→        // Init
363→        renderSearchHistory();
364→        gatherFilters();
365→        loadListings();
366→    }
367→};
