18→    /**
19→     * GET /api/audit
20→     */
21→    public function index()
22→    {
23→        $unmask = (bool) $this->request->get('unmask', false);
24→
25→        // If requesting unmasked data, verify permission
26→        if ($unmask) {
27→            if (!$this->request->user->hasPermission('audit', 'read_unmasked')) {
