 3→namespace app\model;
 4→
 5→use think\Model;
 6→
 7→class Order extends Model
 8→{
 9→    protected $table = 'orders';
10→
11→    protected $autoWriteTimestamp = false;
12→
13→    protected $dateFormat = 'Y-m-d\TH:i:s\Z';
14→
15→    /**
16→     * State machine: maps current status to allowed next statuses.
17→     */
18→    protected const STATE_TRANSITIONS = [
19→        'pending_match' => ['accepted', 'canceled', 'expired'],
20→        'accepted'      => ['in_progress', 'canceled'],
21→        'in_progress'   => ['completed', 'disputed'],
22→        'completed'     => ['disputed'],
23→        'canceled'      => [],
24→        'expired'       => [],
25→        'disputed'      => ['resolved'],
26→        'resolved'      => [],
27→    ];
28→
29→    // ---- Scopes ----
30→
31→    public function scopeOrg($query, int $orgId)
32→    {
33→        return $query->where('org_id', $orgId);
34→    }
35→
36→    // ---- Relationships ----
37→
38→    public function listing()
39→    {
40→        return $this->belongsTo(Listing::class, 'listing_id', 'id');
41→    }
42→
43→    public function passenger()
44→    {
45→        return $this->belongsTo(User::class, 'passenger_id', 'id');
46→    }
47→
48→    public function driver()
49→    {
50→        return $this->belongsTo(User::class, 'driver_id', 'id');
51→    }
52→
53→    public function reviews()
54→    {
55→        return $this->hasMany(Review::class, 'order_id', 'id');
56→    }
57→
58→    // ---- State helpers ----
59→
60→    /**
61→     * Get the list of valid next statuses from the current status.
62→     * Also considers timing rules (e.g., auto-expiry).
63→     *
64→     * @return array
65→     */
66→    public function getAllowedTransitions(): array
67→    {
68→        $current = $this->getData('status');
69→        $allowed = self::STATE_TRANSITIONS[$current] ?? [];
70→
71→        // If pending_match and past expires_at, only expired is valid
72→        if ($current === 'pending_match' && $this->getData('expires_at')) {
73→            $expiresAt = strtotime($this->getData('expires_at'));
74→            if ($expiresAt && $expiresAt <= time()) {
75→                return ['expired'];
76→            }
77→        }
78→
79→        return $allowed;
80→    }
81→
82→    /**
83→     * Check if a given user is a party (passenger or driver) of this order.
84→     *
85→     * @param int $userId
86→     * @return bool
87→     */
88→    public function isParty(int $userId): bool
89→    {
90→        return (int) $this->getData('passenger_id') === $userId
91→            || (int) $this->getData('driver_id') === $userId;
92→    }
93→}
